1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! Small loop-shape rewrites needed before unrolling.
7	//!
8	//! A source loop can have several paths back to its header, usually because it
9	//! contains more than one `continue`. The unroller is much simpler when there is
10	//! one latch, so we route every back-edge through a synthetic block first:
11	//!
12	//! ```text
13	//!   continue_a(values_a) ---> header(args)
14	//!   continue_b(values_b) ---> header(args)
15	//!
16	//! becomes
17	//!
18	//!   continue_a(values_a) -+-> unified_latch(args) -> header(args)
19	//!   continue_b(values_b) -+
20	//! ```
21	//!
22	//! Each old edge keeps the values it passed to the header. The new latch receives
23	//! those values as block arguments and forwards them unchanged. The caller must
24	//! recompute dominance, loop structure, and induction facts after this rewrite.
25	
26	use dialect_mir::ops::MirGotoOp;
27	use pliron::basic_block::BasicBlock;
28	use pliron::builtin::op_interfaces::BranchOpInterface;
29	use pliron::context::Context;
30	use pliron::op::{Op, op_cast};
31	use pliron::operation::Operation;
32	use pliron::r#type::Typed;
33	use pliron::value::Value;
34	use rustc_hash::{FxHashMap, FxHashSet};
35	
36	use crate::analyses::loop_info::{LoopId, LoopInfo};
37	
38	/// Result of trying to put one loop into the single-latch form the unroller
39	/// consumes.
40	pub(crate) enum CanonicalizeOutcome {
41	    /// The loop already had one unconditional back-edge.
42	    Unchanged,
43	    /// The IR was normalized. Cached analyses must be discarded.
44	    Changed,
45	    /// The CFG did not provide enough well-formed edge information to rewrite
46	    /// safely. The caller warns and skips the requested unroll.
47	    Unsupported(String),
48	}
49	
50	/// Route direct outside uses of header-carried values through block arguments.
51	///
52	/// Rust mem2reg can legally leave a header argument in use after an early
53	/// `break`: the header dominates the shared post-loop block. Full unrolling
54	/// cannot replace that use with one final value because each break path needs
55	/// the value from its own copy. This small LCSSA-style rewrite propagates the
56	/// current value from every loop exit through outside forwarding and join
57	/// blocks to each original user.
58	///
59	/// Only header arguments are handled: they dominate every loop block, so each
60	/// exit edge has an unambiguous value. Other loop definitions remain a
61	/// conservative skip in the unroller.
62	pub(crate) fn close_header_liveouts(
63	    ctx: &mut Context,
64	    info: &LoopInfo,
65	    id: LoopId,
66	) -> CanonicalizeOutcome {
67	    let lp = &info.loops()[id];
68	    let header_args: Vec<Value> = lp.header.deref(ctx).arguments().collect();
69	
70	    // Snapshot only the original direct outside uses. Successor operands added
71	    // below are deliberately not candidates for replacement.
72	    let mut liveouts = Vec::new();
73	    let mut user_blocks = FxHashSet::default();
74	    for header_arg in header_args {
75	        let mut outside_uses = Vec::new();
76	        for r#use in header_arg.uses(ctx) {
77	            let Some(block) = r#use.user_op().deref(ctx).get_parent_block() else {
78	                return CanonicalizeOutcome::Unsupported(
79	                    "a loop-carried value has a use outside any basic block".into(),
80	                );
81	            };
82	            if !lp.blocks.contains(&block) {
83	                user_blocks.insert(block);
84	                outside_uses.push(r#use);
85	            }
86	        }
87	        if !outside_uses.is_empty() {
88	            liveouts.push((header_arg, outside_uses));
89	        }
90	    }
91	    if liveouts.is_empty() {
92	        return CanonicalizeOutcome::Unchanged;
93	    }
94	
95	    // Walk backward from every user to the loop boundary. If an outside path
96	    // comes from before the loop, the header value is not available there and a
97	    // local block-argument rewrite is insufficient.
98	    let mut propagation_blocks = FxHashSet::default();
99	    let mut worklist: Vec<_> = user_blocks.into_iter().collect();
100	    while let Some(block) = worklist.pop() {
101	        if !propagation_blocks.insert(block) {
102	            continue;
103	        }
104	        let incoming_edges = block.uses(ctx);
105	        if incoming_edges.is_empty() {
106	            return CanonicalizeOutcome::Unsupported(
107	                "a loop-carried live-out is reachable from outside the loop".into(),
108	            );
109	        }
110	        for edge_use in incoming_edges {
111	            let term = edge_use.user_op();
112	            let Some(source) = term.deref(ctx).get_parent_block() else {
113	                return CanonicalizeOutcome::Unsupported(
114	                    "a live-out predecessor has no basic block".into(),
115	                );
116	            };
117	            let opobj = Operation::get_op_dyn(term, ctx);
118	            if op_cast::<dyn BranchOpInterface>(opobj.as_ref()).is_none() {
119	                return CanonicalizeOutcome::Unsupported(
120	                    "a live-out edge does not expose branch operands".into(),
121	                );
122	            }
123	            if !lp.blocks.contains(&source) {
124	                worklist.push(source);
125	            }
126	        }
127	    }
128	
129	    for (header_arg, original_uses) in liveouts {
130	        // Give every block in the propagation slice a value for this header
131	        // argument before wiring edges, so cycles in outside control flow are
132	        // harmless.
133	        let mut block_values = FxHashMap::default();
134	        let mut arg_indices = FxHashMap::default();
135	        for &block in &propagation_blocks {
136	            let index = BasicBlock::push_argument(block, ctx, header_arg.get_type(ctx));
137	            block_values.insert(block, block.deref(ctx).get_argument(index));
138	            arg_indices.insert(block, index);
139	        }
140	
141	        for &block in &propagation_blocks {
142	            let target_index = arg_indices[&block];
143	            for edge_use in block.uses(ctx) {
144	                let term = edge_use.user_op();
145	                let source = term
146	                    .deref(ctx)
147	                    .get_parent_block()
148	                    .expect("validated predecessor block");
149	                let incoming = if lp.blocks.contains(&source) {
150	                    header_arg
151	                } else {
152	                    block_values[&source]
153	                };
154	                let opobj = Operation::get_op_dyn(term, ctx);
155	                let branch = op_cast::<dyn BranchOpInterface>(opobj.as_ref())
156	                    .expect("validated branch interface");
157	                let appended =
158	                    branch.add_successor_operand(ctx, edge_use.find_index(ctx), incoming);
159	                debug_assert_eq!(appended, target_index);
160	            }
161	        }
162	
163	        for original_use in original_uses {
164	            let block = original_use
165	                .user_op()
166	                .deref(ctx)
167	                .get_parent_block()
168	                .expect("validated live-out user block");
169	            header_arg.replace_use_with(ctx, original_use, &block_values[&block]);
170	        }
171	    }
172	
173	    CanonicalizeOutcome::Changed
174	}
175	
176	/// Merge all back-edges of loop `id` through one block with the header's
177	/// argument signature. This is the `insertUniqueBackedgeBlock` part of LLVM's
178	/// LoopSimplify, kept deliberately small for the unroller's needs.
179	pub(crate) fn merge_backedges(
180	    ctx: &mut Context,
181	    info: &LoopInfo,
182	    id: LoopId,
183	) -> CanonicalizeOutcome {
184	    let lp = &info.loops()[id];
185	
186	    let header = lp.header;
187	    let nargs = header.deref(ctx).get_num_arguments();
188	    let arg_types = header
189	        .deref(ctx)
190	        .arguments()
191	        .map(|arg| arg.get_type(ctx))
192	        .collect();
193	
194	    // Validate every edge before mutating anything. A block can name the header
195	    // more than once, so record successor slots rather than only source blocks.
196	    let mut seen_blocks = FxHashSet::default();
197	    let mut backedges = Vec::new();
198	    for &source in &lp.latches {
199	        if !seen_blocks.insert(source) {
200	            continue;
201	        }
202	        let Some(term) = source.deref(ctx).get_terminator(ctx) else {
203	            return CanonicalizeOutcome::Unsupported(
204	                "a loop back-edge block has no terminator".into(),
205	            );
206	        };
207	        let opobj = Operation::get_op_dyn(term, ctx);
208	        let Some(branch) = op_cast::<dyn BranchOpInterface>(opobj.as_ref()) else {
209	            return CanonicalizeOutcome::Unsupported(
210	                "a loop back-edge terminator does not expose branch operands".into(),
211	            );
212	        };
213	        for (succ_idx, succ) in term.deref(ctx).successors().enumerate() {
214	            if succ == header {
215	                if branch.successor_operands(ctx, succ_idx).len() != nargs {
216	                    return CanonicalizeOutcome::Unsupported(
217	                        "a loop back-edge carries the wrong number of header values".into(),
218	                    );
219	                }
220	                backedges.push((term, succ_idx));
221	            }
222	        }
223	    }
224	    if backedges.is_empty() {
225	        return CanonicalizeOutcome::Unsupported(
226	            "LoopInfo reported a loop but no back-edge to its header was found".into(),
227	        );
228	    }
229	    if backedges.len() == 1 {
230	        let (term, succ_idx) = backedges[0];
231	        let successors: Vec<_> = term.deref(ctx).successors().collect();
232	        if succ_idx == 0
233	            && successors == [header]
234	            && Operation::get_op::<MirGotoOp>(term, ctx).is_some()
235	        {
236	            return CanonicalizeOutcome::Unchanged;
237	        }
238	    }
239	
240	    let unified = BasicBlock::new(ctx, None, arg_types);
241	    unified.insert_before(ctx, header);
242	
243	    // Build the forwarding edge before retargeting old edges. With recorded
244	    // successor slots either order is correct; doing this first also makes the
245	    // intended block shape explicit throughout the mutation.
246	    let args = unified.deref(ctx).arguments().collect();
247	    let goto = Operation::new(
248	        ctx,
249	        MirGotoOp::get_concrete_op_info(),
250	        vec![],
251	        args,
252	        vec![header],
253	        0,
254	    );
255	    goto.insert_at_back(unified, ctx);
256	
257	    for (term, succ_idx) in backedges {
258	        Operation::replace_successor(term, ctx, succ_idx, unified);
259	    }
260	    CanonicalizeOutcome::Changed
261	}
262

