1	/*
2	 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
3	 * SPDX-License-Identifier: Apache-2.0
4	 */
5	
6	//! Loop unrolling, switched on by a `#[unroll]` annotation.
7	//!
8	//! Unrolling means making copies of a loop body so the loop runs fewer times
9	//! (or not at all), trading bigger code for less per-iteration overhead and more
10	//! chances to optimise. For example:
11	//!
12	//! ```text
13	//!   i = 0; while i < 4 { f(i); i += 1 }   becomes:   f(0); f(1); f(2); f(3);
14	//! ```
15	//!
16	//! `#[unroll]` requests full unrolling when the iteration count is known at
17	//! compile time. `#[unroll(N)]` requests `N` body copies per trip and leaves a
18	//! small remainder loop for leftover iterations. The frontend records the
19	//! request as a `mir.unroll_hint` operation inside that loop.
20	//!
21	//! The current analysis recognizes explicit counted `while` loops. Range-based
22	//! `for` loops are not yet recognized.
23	//!
24	//! Several `continue` paths are supported: the pass joins their back-edges
25	//! before unrolling. Full `#[unroll]` also preserves early `break` paths and
26	//! multiple exit targets. Partial `#[unroll(N)]` warns and leaves the loop not
27	//! unrolled when it has an extra exit. Partial unrolling currently requires a
28	//! positive step, a `<` or `<=` test, and a loop-invariant bound.
29	//!
30	//! To bound compile time and memory, one request may create at most 1,024 body
31	//! copies, 8,192 cloned blocks, and 65,536 cloned operations. Larger requests
32	//! warn and are not unrolled.
33	//!
34	//! If an annotated loop contains another loop, only the annotated loop is
35	//! unrolled. The inner loop is copied intact into each body copy and remains a
36	//! loop. Give the inner loop its own annotation if it should be unrolled too.
37	//!
38	//! This pass is the reference example for writing an optimisation pass in oxide.
39	//! It builds on two reusable analyses, [`LoopInfo`](crate::analyses::loop_info)
40	//! (finds the loops) and [`induction`] (finds the counters and how many times
41	//! each loop runs), and on pliron's IR cloning (`pliron::irbuild::cloning`) to
42	//! duplicate the body.
43	
44	use dialect_mir::ops::arithmetic::{MirAddOp, MirBitAndOp, MirRemOp, MirSubOp};
45	use dialect_mir::ops::comparison::{MirGeOp, MirGtOp, MirLeOp, MirLtOp};
46	use dialect_mir::ops::constants::MirConstantOp;
47	use dialect_mir::ops::control_flow::{MirCondBranchOp, MirGotoOp, MirUnrollHintOp};
48	use dialect_mir::ops::function::MirFuncOp;
49	use dialect_mir::ops::{MirStorageDeadOp, MirStorageLiveOp};
50	use pliron::basic_block::BasicBlock;
51	use pliron::builtin::attributes::IntegerAttr;
52	use pliron::builtin::op_interfaces::OperandSegmentInterface;
53	use pliron::builtin::types::{IntegerType, Signedness};
54	use pliron::context::{Context, Ptr};
55	use pliron::graph::ControlFlowGraph;
56	use pliron::graph::dominance::DomInfo;
57	use pliron::irbuild::{
58	    cloning::{IrMapping, clone_blocks_into},
59	    listener::DummyListener,
60	    rewriter::IRRewriter,
61	};
62	use pliron::linked_list::ContainsLinkedList;
63	use pliron::op::{Op, op_cast};
64	use pliron::operation::Operation;
65	use pliron::opts::constants::sccp::sccp;
66	use pliron::opts::dce::{SideEffects, dce};
67	use pliron::opts::simplify_cfg::simplify_cfg;
68	use pliron::pass_manager::AnalysisManager;
69	use pliron::region::Region;
70	use pliron::result::Result;
71	use pliron::r#type::{TypeHandle, Typed, TypedHandle};
72	use pliron::utils::apint::APInt;
73	use pliron::value::Value;
74	use rustc_hash::FxHashSet;
75	use std::num::NonZero;
76	
77	use crate::analyses::induction::{self, ArgKind, CmpPred};
78	use crate::analyses::loop_info::LoopInfo;
79	use crate::canonicalize::{CanonicalizeOutcome, close_header_liveouts, merge_backedges};
80	
81	/// Hard safety limit on how many body copies one annotation may request.
82	/// Explicit annotations still need a bound: accepting an arbitrary `u32`
83	/// factor or `u64` trip count would let valid source exhaust the compiler.
84	const MAX_UNROLL_COPIES: u64 = 1_024;
85	
86	/// Hard safety limit on the total number of basic blocks cloned by one unroll.
87	/// This separately bounds large and nested bodies even when their copy count is
88	/// below [`MAX_UNROLL_COPIES`].
89	const MAX_CLONED_BLOCKS: u64 = 8_192;
90	
91	/// Hard safety limit on the total number of operations cloned by one unroll.
92	/// A block budget alone is insufficient because one block may contain an
93	/// arbitrarily large straight-line body.
94	const MAX_CLONED_OPS: u64 = 65_536;
95	
96	fn verbose() -> bool {
97	    std::env::var("CUDA_OXIDE_VERBOSE").is_ok()
98	}
99	
100	/// How the author spelled the request, for diagnostics: `#[unroll]` (full) or
101	/// `#[unroll(N)]` (partial by N).
102	fn unroll_kind(factor: u32) -> String {
103	    if factor == 0 {
104	        "#[unroll]".to_string()
105	    } else {
106	        format!("#[unroll({factor})]")
107	    }
108	}
