110	/// Check code-growth budgets whose inputs have already been counted safely.
111	fn check_growth_budget(
112	    copies: u64,
113	    blocks_per_copy: u64,
114	    ops_per_copy: u64,
115	) -> std::result::Result<(), String> {
116	    if copies > MAX_UNROLL_COPIES {
117	        return Err(format!(
118	            "unrolling would create {copies} body copies; the safety limit is {MAX_UNROLL_COPIES}"
119	        ));
120	    }
121	    let total_blocks = copies
122	        .checked_mul(blocks_per_copy)
123	        .ok_or_else(|| "the requested unroll is too large to budget safely".to_string())?;
124	    if total_blocks > MAX_CLONED_BLOCKS {
125	        return Err(format!(
126	            "unrolling would clone {total_blocks} body blocks ({copies} copies x {blocks_per_copy} blocks); the safety limit is {MAX_CLONED_BLOCKS} cloned blocks"
127	        ));
128	    }
129	    let total_ops = copies
130	        .checked_mul(ops_per_copy)
131	        .ok_or_else(|| "the requested unroll is too large to budget safely".to_string())?;
132	    if total_ops > MAX_CLONED_OPS {
133	        return Err(format!(
134	            "unrolling would clone {total_ops} operations ({copies} copies x {ops_per_copy} operations); the safety limit is {MAX_CLONED_OPS} cloned operations"
135	        ));
136	    }
137	    Ok(())
138	}
139	
140	/// Count one body copy and check every code-growth budget before cloning.
141	fn check_clone_budget(
142	    ctx: &Context,
143	    copies: u64,
144	    body_blocks: &[Ptr<BasicBlock>],
145	) -> std::result::Result<(), String> {
146	    let blocks_per_copy = u64::try_from(body_blocks.len())
147	        .map_err(|_| "the loop body is too large to budget safely".to_string())?;
148	    let mut ops_per_copy = 0u64;
149	    for &block in body_blocks {
150	        let block_ops = u64::try_from(block.deref(ctx).iter(ctx).count())
151	            .map_err(|_| "the loop body has too many operations to budget safely".to_string())?;
152	        ops_per_copy = ops_per_copy
153	            .checked_add(block_ops)
154	            .ok_or_else(|| "the loop body has too many operations to budget safely".to_string())?;
155	    }
156	    check_growth_budget(copies, blocks_per_copy, ops_per_copy)
157	}
