159	/// Unroll each loop that carries an in-body `mir.unroll_hint`, which the
160	/// frontend plants for `#[unroll]` and `#[unroll(N)]`. Other functions are left
161	/// untouched.
162	///
163	/// Within each annotated function, this finds loops with [`LoopInfo`], maps
164	/// every hint to its loop, joins multiple back-edges through one latch, analyzes
165	/// the loop counter, and performs full or partial unrolling. It recomputes loop
166	/// and induction facts after normalization. Annotated nested loops are processed
167	/// from the inside out. Afterward, SCCP, CFG simplification, and dead-code
168	/// elimination clean only that function: constant index expressions fold, dead
169	/// branches disappear, and unreachable original loop blocks are removed.
170	///
171	/// Unsupported loop shapes produce a warning and are not unrolled.
172	pub fn unroll_annotated_loops(
173	    module: Ptr<Operation>,
174	    ctx: &mut Context,
175	    // The caller threads in the manager mem2reg used. We deliberately do not use
176	    // it: the CFG-normalization step below changes block structure, which would
177	    // stale that manager's cached dominator trees. We build a fresh manager
178	    // afterwards instead. (Kept in the signature to match pliron's pass shape.)
179	    _analyses: &mut AnalysisManager,
180	) -> Result<()> {
181	    // Nothing annotated => leave every function byte-for-byte untouched.
182	    let has_hints = collect_functions(module, ctx)
183	        .iter()
184	        .any(|&f| !collect_hints(ctx, f.deref(ctx).get_region(0)).is_empty());
185	    if !has_hints {
186	        return Ok(());
187	    }
188	
189	    let mut changed = false;
190	    for func_op in collect_functions(module, ctx) {
191	        let region = func_op.deref(ctx).get_region(0);
192	        if collect_hints(ctx, region).is_empty() {
193	            continue;
194	        }
195	        let mut function_changed = false;
196	
197	        // Normalize only the annotated function. The marker call often gets its
198	        // own MIR block; `simplify_cfg` merges that block back into the loop body
199	        // without changing unrelated functions in the module.
200	        simplify_cfg(func_op, ctx)?;
201	
202	        // Unroll one annotated loop per round, innermost-first, recomputing the
203	        // loop analyses each round. Each unroll rewrites the CFG -- and for a loop
204	        // that *contains* inner loops it clones those inner loops into every copy
205	        // -- so a single shared `LoopInfo` snapshot would go stale. A fresh
206	        // dominator tree + `LoopInfo` per round keeps every query correct; we run
207	        // `simplify_cfg` first so the recompute sees only live blocks (a full
208	        // unroll leaves the original loop unreachable, and we must not let those
209	        // dead blocks confuse dominance). Innermost-first means an annotated inner
210	        // loop is unrolled, and its hint consumed, before its enclosing loop is
211	        // cloned, so inner hints are never duplicated into the copies. (`dce` is
212	        // deliberately NOT run here: it would delete the side-effect-free
213	        // `mir.unroll_hint` markers before we get to collect them.)
214	        let mut skip_simplify_once = false;
215	        loop {
216	            // Drop blocks the previous round made unreachable before recomputing.
217	            // Do not immediately simplify a newly inserted unified latch: a CFG
218	            // cleanup could fold that forwarding block away before the fresh
219	            // loop analysis gets to use it.
220	            if skip_simplify_once {
221	                skip_simplify_once = false;
222	            } else {
223	                simplify_cfg(func_op, ctx)?;
224	            }
225	
226	            let hints = collect_hints(ctx, region);
227	            if hints.is_empty() {
228	                break;
229	            }
230	
231	            let info = {
232	                let mut analyses = AnalysisManager::default();
233	                let mut dom_info = analyses.get_analysis_mut::<DomInfo>(module, ctx)?;
234	                let dom = dom_info.get_dom_tree(ctx, region);
235	                LoopInfo::compute(ctx, region, dom)
236	            };
237	
238	            // Pick the innermost annotated loop still to do (smallest body wins;
239	            // in a reducible CFG a container's body is a strict superset of its
240	            // child's, so "smallest body" is exactly "innermost").
241	            let mut best: Option<(usize, usize, u32)> = None; // (loop_id, body_size, factor)
242	            for (_op, block, factor) in &hints {
243	                if let Some(loop_id) = info.innermost_loop(*block) {
244	                    let size = info.loops()[loop_id].blocks.len();
245	                    if best.is_none_or(|(_, bs, _)| size < bs) {
246	                        best = Some((loop_id, size, *factor));
247	                    }
248	                }
249	            }
250	            let Some((loop_id, _size, factor)) = best else {
251	                // No remaining hint sits in a recognizable loop. The author asked
252	                // for unrolling, so say so loudly, then drop the markers and stop.
253	                for (op, _block, factor) in &hints {
254	                    eprintln!(
255	                        "warning: {} requested but the loop was not unrolled: the annotation is not inside a recognizable loop",
256	                        unroll_kind(*factor)
257	                    );
258	                    op.unlink(ctx);
259	                }
260	                break;
261	            };
262	            let kind = unroll_kind(factor);
263	
264	            let Some(ph) = info.preheader(ctx, region, loop_id) else {
265	                // The author asked for unrolling; never silently do nothing.
266	                for (op, block, _f) in &hints {
267	                    if info.innermost_loop(*block) == Some(loop_id) {
268	                        op.unlink(ctx);
269	                    }
270	                }
271	                eprintln!(
272	                    "warning: {kind} requested but the loop was not unrolled: it has no single preheader (it is entered from more than one place)"
273	                );
274	                continue;
275	            };
276	
277	            // A grouped main loop plus a remainder loop needs explicit merging
278	            // for every early-exit value. Keep that as a follow-up: full unroll
279	            // can preserve those paths directly, partial unroll warns and skips.
280	            if factor != 0 {
281	                let lp = &info.loops()[loop_id];
282	                let exiting = info.exiting_blocks(ctx, region, loop_id);
283	                let exits = info.exit_blocks(ctx, region, loop_id);
284	                if exiting.len() != 1 || exiting[0] != lp.header || exits.len() != 1 {
285	                    for (op, block, _f) in &hints {
286	                        if info.innermost_loop(*block) == Some(loop_id) {
287	                            op.unlink(ctx);
288	                        }
289	                    }
290	                    eprintln!(
291	                        "warning: {kind} requested but the loop was not unrolled: partial unrolling does not yet support an early `break` or multiple exits"
292	                    );
293	                    continue;
294	                }
295	            }
296	
297	            // Full unroll needs path-specific values at early exits. Route any
298	            // directly used header arguments through outside block arguments
299	            // before cloning, then recompute analyses over the normalized IR.
300	            if factor == 0 {
301	                match close_header_liveouts(ctx, &info, loop_id) {
302	                    CanonicalizeOutcome::Unchanged => {}
303	                    CanonicalizeOutcome::Changed => {
304	                        function_changed = true;
305	                        changed = true;
306	                        skip_simplify_once = true;
307	                        continue;
308	                    }
309	                    CanonicalizeOutcome::Unsupported(reason) => {
310	                        for (op, block, _f) in &hints {
311	                            if info.innermost_loop(*block) == Some(loop_id) {
312	                                op.unlink(ctx);
313	                            }
314	                        }
315	                        eprintln!(
316	                            "warning: {kind} requested but the loop was not unrolled: could not route its live-out values: {reason}"
317	                        );
318	                        continue;
319	                    }
320	                }
321	            }
322	
323	            // Normalize every continue/back-edge through one unconditional
324	            // latch. Leave the hint in place when the CFG changes so the next
325	            // round can recompute dominance, loops, and induction facts first.
326	            match merge_backedges(ctx, &info, loop_id) {
327	                CanonicalizeOutcome::Unchanged => {}
328	                CanonicalizeOutcome::Changed => {
329	                    function_changed = true;
330	                    changed = true;
331	                    skip_simplify_once = true;
332	                    continue;
333	                }
334	                CanonicalizeOutcome::Unsupported(reason) => {
335	                    for (op, block, _f) in &hints {
336	                        if info.innermost_loop(*block) == Some(loop_id) {
337	                            op.unlink(ctx);
338	                        }
339	                    }
340	                    eprintln!(
341	                        "warning: {kind} requested but the loop was not unrolled: could not normalize its back-edges: {reason}"
342	                    );
343	                    continue;
344	                }
345	            }
346	
347	            // Consume this loop's hint(s) before any cloning so the markers are
348	            // never copied into the unrolled bodies.
349	            for (op, block, _f) in &hints {
350	                if info.innermost_loop(*block) == Some(loop_id) {
351	                    op.unlink(ctx);
352	                }
353	            }
354	
355	            let rec = induction::analyze(ctx, &info, loop_id, ph);
356	            if verbose() {
357	                eprintln!(
358	                    "loop-unroll: loop#{loop_id} factor={factor} trip={:?} primary_iv={:?}",
359	                    rec.trip_count, rec.primary_iv,
360	                );
361	            }
362	            let outcome = if factor == 0 {
363	                // Full unroll: only works when the trip count is a constant.
364	                full_unroll(ctx, &info, region, loop_id, ph, &rec)?
365	            } else {
366	                // Partial unroll by `factor`, with a remainder loop for the tail.
367	                partial_unroll(ctx, &info, region, loop_id, ph, &rec, factor)?
368	            };
369	            match outcome {
370	                UnrollOutcome::Unrolled => {
371	                    function_changed = true;
372	                    changed = true;
373	                }
374	                // Requested but unsupported shape: report exactly why, loudly, so
375	                // it is never a silent no-op.
376	                UnrollOutcome::Skipped(reason) => {
377	                    eprintln!("warning: {kind} requested but the loop was not unrolled: {reason}");
378	                }
379	            }
380	        }
381	        if function_changed {
382	            // Fold and clean only this function. `sccp` folds constant index
383	            // arithmetic and branch conditions, `simplify_cfg` removes dead
384	            // paths and original loop blocks, and `dce` removes unused ops.
385	            // The outer filter ensures this cleanup never touches a function
386	            // with no unroll annotation.
387	            sccp(func_op, ctx)?;
388	            simplify_cfg(func_op, ctx)?;
389	            dce(func_op, ctx)?;
390	        }
391	    }
392	
393	    if changed {
394	        // The input was verified before this pass, so a failure here is a bug in
395	        // the unroller. Verify after cleanup, when unreachable original loop
396	        // blocks are gone and the dominator-based verifier sees the final CFG.
397	        pliron::operation::verify_operation(module, ctx)?;
398	    }
399	    Ok(())
400	}
