402	/// What happened when we tried to unroll one loop.
403	enum UnrollOutcome {
404	    /// The loop was unrolled; the IR changed.
405	    Unrolled,
406	    /// The loop was not unrolled, with a plain-English reason. The caller turns
407	    /// this into a loud warning (the author asked for unrolling, so we never
408	    /// silently do nothing). Earlier normalization may still have rewritten its CFG.
409	    Skipped(String),
410	}
411	
412	/// The facts the unroller needs about a loop, gathered once and shared by full
413	/// and partial unroll, plus the checks that the loop is in the shape we support.
414	///
415	/// v1 supports a loop with **arbitrary internal control flow** (the body may be
416	/// many blocks: `if`/`else`, `match`, `&&`/`||`) and may contain nested
417	/// loops. Multiple source latches have already been merged into one canonical
418	/// latch. Full unrolling accepts early exits and multiple exit targets. Partial
419	/// unrolling additionally requires the header test to be the only exit. Both
420	/// modes require a recognized counter, a dedicated preheader, and a header with
421	/// only pure guard calculations before its conditional branch. `analyze_shape`
422	/// returns `Err(reason)` for anything else.
423	///
424	/// We deliberately do **not** clone the header. The header holds the loop's
425	/// carried values as block arguments (the counter and any accumulators); the
426	/// body reads those by dominance. Cloning only the body and substituting those
427	/// arguments per copy keeps the counter a literal in each copy (the property that
428	/// lets `i & 3` fold). A header that *computes* a value the body reads would
429	/// break that, so we reject it (`Err`) and leave header-cloning to a follow-up.
430	struct LoopShape {
431	    header: Ptr<BasicBlock>,
432	    latch: Ptr<BasicBlock>,
433	    /// The outside successor of the header's ordinary loop test.
434	    normal_exit: Ptr<BasicBlock>,
435	    /// Whether some body block can leave without going through the latch.
436	    has_early_exits: bool,
437	    /// The header's single in-loop successor: the first block of the body.
438	    body_entry: Ptr<BasicBlock>,
439	    /// Every body block (the loop minus the header) forward-reachable from
440	    /// `body_entry`, in a deterministic visit order. `clone_blocks_into` is
441	    /// order-independent, so the order is not load-bearing; we keep a stable
442	    /// order only for readable IR dumps. Its length (vs the body-block count) is
443	    /// what detects unreachable / irreducible body blocks (see
444	    /// [`reachable_body_blocks`]).
445	    body_blocks_ordered: Vec<Ptr<BasicBlock>>,
446	    /// The header's block arguments (the loop-carried values, counter included).
447	    header_args: Vec<Value>,
448	    nargs: usize,
449	    /// preheader -> header operands (the loop's initial carried values).
450	    init_ops: Vec<Value>,
451	    /// latch -> header operands (the updated carried values each iteration).
452	    recur_ops: Vec<Value>,
453	    /// header -> body_entry operands (args the header passes into the body).
454	    entry_ops: Vec<Value>,
455	    /// header -> normal_exit operands (the normal-completion live-out values).
456	    normal_exit_ops: Vec<Value>,
457	    iv_idx: usize,
458	    iv_init: i128,
459	    iv_step: i128,
460	    iv_type: TypeHandle,
461	    /// The boolean type of the header's exit test (for any new comparison).
462	    i1_type: TypeHandle,
463	    /// The preheader's terminator (a plain branch to the header).
464	    preheader_term: Ptr<Operation>,
465	    /// Every block of the loop (header included). Used to tell loop-internal uses
466	    /// of the carried values from out-of-loop (live-out) uses.
467	    loop_blocks: FxHashSet<Ptr<BasicBlock>>,
468	}
469	
470	/// True if `v` is the result of an operation located in one of `set`'s blocks
471	/// (a block argument, having no defining op, is not "defined in" the set this
472	/// way). Used to tell loop-variant values from loop-invariant ones.
473	fn defined_in_loop(ctx: &Context, v: Value, set: &FxHashSet<Ptr<BasicBlock>>) -> bool {
474	    v.defining_op()
475	        .and_then(|d| d.deref(ctx).get_parent_block())
476	        .map(|b| set.contains(&b))
477	        .unwrap_or(false)
478	}
479	
480	/// The blocks of `set` forward-reachable from `entry`, following only edges that
481	/// stay inside `set`, in a deterministic visit order.
482	///
483	/// `clone_blocks_into` is order-independent (it records every clone block, block
484	/// argument, and op result before wiring any operand or successor), so the order
485	/// here is not required for cloning; a plain reachability walk is enough. We keep
486	/// the result ordered only so IR dumps are stable. Its main job is the soundness
487	/// check at the call site: if it is shorter than `set`, some body block reaches
488	/// the latch but is not reachable from the single entry, i.e. irreducible /
489	/// multi-entry control flow the v1 shape does not support.
490	fn reachable_body_blocks(
491	    ctx: &Context,
492	    region: Ptr<Region>,
493	    entry: Ptr<BasicBlock>,
494	    set: &FxHashSet<Ptr<BasicBlock>>,
495	) -> Vec<Ptr<BasicBlock>> {
496	    let mut visited: FxHashSet<Ptr<BasicBlock>> = FxHashSet::default();
497	    let mut order: Vec<Ptr<BasicBlock>> = Vec::new();
498	    let mut stack: Vec<Ptr<BasicBlock>> = vec![entry];
499	    while let Some(b) = stack.pop() {
500	        if !visited.insert(b) {
501	            continue;
502	        }
503	        order.push(b);
504	        for s in region.successors(ctx, &b) {
505	            if set.contains(&s) && !visited.contains(&s) {
506	                stack.push(s);
507	            }
508	        }
509	    }
510	    order
511	}
512	
513	/// Gather the loop facts and confirm the v1 shape. See [`LoopShape`].
514	fn analyze_shape(
515	    ctx: &Context,
516	    info: &LoopInfo,
517	    region: Ptr<Region>,
518	    id: usize,
519	    preheader: Ptr<BasicBlock>,
520	    rec: &induction::LoopRecurrences,
521	    allow_early_exits: bool,
522	) -> std::result::Result<LoopShape, String> {
523	    let l = &info.loops()[id];
524	    // A loop that *contains* an inner loop can be unrolled: the inner loop's
525	    // blocks are part of this loop's body (`l.blocks`), so cloning the body
526	    // clones the inner loop wholesale and it stays a loop in each copy -- we do
527	    // not recurse into it or unroll it. Unrolling the inner loop too is a
528	    // separate `#[unroll]` on the inner loop, which the driver processes
529	    // innermost-first; and the driver recomputes `LoopInfo` after each unroll so
530	    // the cloned inner loops are re-registered cleanly. So `l.children` is no
531	    // longer a bail; inner loops are opaque body blocks to the clone.
532	    if l.latches.len() != 1 {
533	        return Err(format!(
534	            "the loop has {} back-edges after canonicalization; expected one unified latch",
535	            l.latches.len()
536	        ));
537	    }
538	    let header = l.header;
539	    let latch = l.latches[0];
540	
541	    let iv_idx = rec
542	        .primary_iv
543	        .ok_or("no recognized induction variable (loop counter)")?;
544	    let (iv_init, iv_step) = match &rec.args[iv_idx] {
545	        ArgKind::BasicIv { init, step } => (*init, *step),
546	        _ => return Err("the loop counter is not a simple induction variable".into()),
547	    };
548	
549	    // The header has one ordinary body successor and one ordinary exit. Other
550	    // body blocks may have their own outside successors on the full-unroll path.
551	    let header_term = header
552	        .deref(ctx)
553	        .get_terminator(ctx)
554	        .ok_or("the header has no terminator")?;
555	    if Operation::get_op::<MirCondBranchOp>(header_term, ctx).is_none() {
556	        return Err("the loop header must end in a mir.cond_br exit test".into());
557	    }
558	    // Full unrolling removes the header, and partial unrolling bypasses it for
559	    // grouped iterations. Either transform would change observable header work.
560	    // Storage lifetime markers are harmless: lowering erases them and emits no
561	    // runtime instruction.
562	    for op in header.deref(ctx).iter(ctx) {
563	        let harmless_marker = Operation::get_op::<MirStorageLiveOp>(op, ctx).is_some()
564	            || Operation::get_op::<MirStorageDeadOp>(op, ctx).is_some();
565	        if op == header_term || harmless_marker {
566	            continue;
567	        }
568	        let opobj = Operation::get_op_dyn(op, ctx);
569	        let may_have_side_effects = op_cast::<dyn SideEffects>(opobj.as_ref())
570	            .is_none_or(|effects| effects.has_side_effects(ctx));
571	        if may_have_side_effects {
572	            return Err(
573	                "the loop header contains an operation with possible side effects; move that work into the body before unrolling"
574	                    .into(),
575	            );
576	        }
577	    }
578	    let successors: Vec<Ptr<BasicBlock>> = header_term.deref(ctx).successors().collect();
579	    let in_loop: Vec<_> = successors
580	        .iter()
581	        .copied()
582	        .filter(|s| l.blocks.contains(s))
583	        .collect();
584	    let outside: Vec<_> = successors
585	        .iter()
586	        .copied()
587	        .filter(|s| !l.blocks.contains(s))
588	        .collect();
589	    if in_loop.len() != 1 || outside.len() != 1 {
590	        return Err("the loop header must have one body edge and one normal exit edge".into());
591	    }
592	    let body_entry = in_loop[0];
593	    let normal_exit = outside[0];
594	
595	    let exiting = info.exiting_blocks(ctx, region, id);
596	    let exits = info.exit_blocks(ctx, region, id);
597	    let has_early_exits = exiting.iter().any(|&block| block != header);
598	    if !allow_early_exits && (has_early_exits || exits.len() != 1) {
599	        return Err(
600	            "partial unrolling does not yet support an early `break` or multiple exits".into(),
601	        );
602	    }
603	
604	    // The preheader must end in a plain branch to the header (dedicated preheader).
605	    let preheader_term = preheader
606	        .deref(ctx)
607	        .get_terminator(ctx)
608	        .ok_or("the preheader has no terminator")?;
609	    let p_succs: Vec<Ptr<BasicBlock>> = preheader_term.deref(ctx).successors().collect();
610	    if Operation::get_op::<MirGotoOp>(preheader_term, ctx).is_none() || p_succs != [header] {
611	        return Err("the loop preheader must end in a mir.goto to the header".into());
612	    }
613	
614	    // The latch must end in a plain back-edge to the header.
615	    let latch_term = latch
616	        .deref(ctx)
617	        .get_terminator(ctx)
618	        .ok_or("the latch has no terminator")?;
619	    let l_succs: Vec<Ptr<BasicBlock>> = latch_term.deref(ctx).successors().collect();
620	    if Operation::get_op::<MirGotoOp>(latch_term, ctx).is_none() || l_succs != [header] {
621	        return Err("the loop latch must end in a mir.goto back to the header".into());
622	    }
623	
624	    let nargs = header.deref(ctx).get_num_arguments();
625	    let header_args: Vec<Value> = (0..nargs)
626	        .map(|i| header.deref(ctx).get_argument(i))
627	        .collect();
628	    let iv_type = header_args[iv_idx].get_type(ctx);
629	    let i1_type = header_term.deref(ctx).get_operand(0).get_type(ctx);
630	
631	    let init_ops = induction::edge_operands(ctx, preheader, header)
632	        .filter(|v| v.len() == nargs)
633	        .ok_or("preheader carried-value arity mismatch")?;
634	    let recur_ops = induction::edge_operands(ctx, latch, header)
635	        .filter(|v| v.len() == nargs)
636	        .ok_or("latch carried-value arity mismatch")?;
637	    let entry_ops = induction::edge_operands(ctx, header, body_entry).unwrap_or_default();
638	    let normal_exit_ops = induction::edge_operands(ctx, header, normal_exit).unwrap_or_default();
639	
640	    // Clean-header check (see [`LoopShape`]): the body must not read any value the
641	    // header *computes*. Reading the header's block arguments is fine (we
642	    // substitute those per copy); reading a header op result is not.
643	    let body_blocks: FxHashSet<Ptr<BasicBlock>> =
644	        l.blocks.iter().copied().filter(|&b| b != header).collect();
645	    let defined_in_header = |ctx: &Context, v: Value| -> bool {
646	        v.defining_op()
647	            .map(|d| d.deref(ctx).get_parent_block() == Some(header))
648	            .unwrap_or(false)
649	    };
650	    for &b in &body_blocks {
651	        for op in b.deref(ctx).iter(ctx).collect::<Vec<_>>() {
652	            let nops = op.deref(ctx).get_num_operands();
653	            for o in 0..nops {
654	                if defined_in_header(ctx, op.deref(ctx).get_operand(o)) {
655	                    return Err("the header computes a value the body reads; this shape needs header cloning (a follow-up)".into());
656	                }
657	            }
658	        }
659	    }
660	    for &v in &entry_ops {
661	        if defined_in_header(ctx, v) {
662	            return Err("the header passes a computed value into the body; this shape needs header cloning (a follow-up)".into());
663	        }
664	    }
665	    // Same for live-outs: a header *block argument* the exit reads is handled (we
666	    // substitute the final value), but a header op *result* on the exit edge
667	    // would dangle once full unroll deletes the header. Reject it loudly.
668	    for &v in &normal_exit_ops {
669	        if defined_in_header(ctx, v) {
670	            return Err("the header computes a live-out value the exit reads; this shape needs header cloning (a follow-up)".into());
671	        }
672	    }
673	
674	    let body_blocks_ordered = reachable_body_blocks(ctx, region, body_entry, &body_blocks);
675	    if body_blocks_ordered.len() != body_blocks.len() {
676	        return Err("the loop body has blocks unreachable from its entry (irreducible control flow); not supported".into());
677	    }
678	
679	    Ok(LoopShape {
680	        header,
681	        latch,
682	        normal_exit,
683	        has_early_exits,
684	        body_entry,
685	        body_blocks_ordered,
686	        header_args,
687	        nargs,
688	        init_ops,
689	        recur_ops,
690	        entry_ops,
691	        normal_exit_ops,
692	        iv_idx,
693	        iv_init,
694	        iv_step,
695	        iv_type,
696	        i1_type,
697	        preheader_term,
698	        loop_blocks: l.blocks.clone(),
699	    })
700	}
