702	/// One cloned copy of the loop body.
703	struct CopyResult {
704	    /// The clone of `body_entry`: where control enters this copy.
705	    entry: Ptr<BasicBlock>,
706	    /// The clone of the latch's terminator (its back-edge `goto header`), which
707	    /// the caller repoints to the next copy (or the exit).
708	    latch_term: Ptr<Operation>,
709	    /// The carried values this copy produces, to feed the next copy (the latch's
710	    /// back-edge operands, mapped through this copy's substitution).
711	    next_running: Vec<Value>,
712	    /// The operands to pass when branching into `entry` (the header -> body_entry
713	    /// operands, mapped through this copy's substitution).
714	    entry_args: Vec<Value>,
715	    /// This copy's cloned blocks, in the same order as
716	    /// `LoopShape::body_blocks_ordered`.
717	    blocks: Vec<Ptr<BasicBlock>>,
718	}
719	
720	/// Clone one copy of the loop body, substituting `subst[a]` for header argument
721	/// `a` (so `subst` carries this copy's counter value and accumulators). The
722	/// clone's internal branches and block-argument passes are remapped
723	/// automatically by [`clone_blocks_into`]; the caller wires the boundary edges.
724	fn clone_one_copy(
725	    ctx: &mut Context,
726	    region: Ptr<Region>,
727	    s: &LoopShape,
728	    subst: &[Value],
729	) -> CopyResult {
730	    let mut mapper = IrMapping::new();
731	    for (a, &hv) in s.header_args.iter().enumerate() {
732	        mapper.map_value(hv, subst[a]);
733	    }
734	    // Operands for the edge that enters this copy: the header -> body_entry
735	    // operands with this copy's carried values substituted in. Computed before
736	    // cloning (they reference only header args / outer values, never body values).
737	    let entry_args: Vec<Value> = s
738	        .entry_ops
739	        .iter()
740	        .map(|&v| mapper.lookup_value_or_default(v))
741	        .collect();
742	    let mut rewriter = IRRewriter::<DummyListener>::default();
743	    clone_blocks_into(
744	        &s.body_blocks_ordered,
745	        region,
746	        ctx,
747	        &mut rewriter,
748	        &mut mapper,
749	    );
750	    let entry = mapper.lookup_block_or_default(s.body_entry);
751	    let latch = mapper.lookup_block_or_default(s.latch);
752	    let latch_term = latch
753	        .deref(ctx)
754	        .get_terminator(ctx)
755	        .expect("a cloned latch has a terminator");
756	    let next_running: Vec<Value> = s
757	        .recur_ops
758	        .iter()
759	        .map(|&v| mapper.lookup_value_or_default(v))
760	        .collect();
761	    let blocks: Vec<Ptr<BasicBlock>> = s
762	        .body_blocks_ordered
763	        .iter()
764	        .map(|&b| mapper.lookup_block_or_default(b))
765	        .collect();
766	    CopyResult {
767	        entry,
768	        latch_term,
769	        next_running,
770	        entry_args,
771	        blocks,
772	    }
773	}
