775	/// Repoint a single-successor branch (`goto`) at `new_succ`, replacing all its
776	/// edge operands with `operands`.
777	fn rewire_goto(
778	    ctx: &mut Context,
779	    term: Ptr<Operation>,
780	    new_succ: Ptr<BasicBlock>,
781	    operands: &[Value],
782	) {
783	    Operation::replace_successor(term, ctx, 0, new_succ);
784	    let n = term.deref(ctx).get_num_operands();
785	    for _ in 0..n {
786	        Operation::remove_operand(term, ctx, 0);
787	    }
788	    for &v in operands {
789	        Operation::push_operand(term, ctx, v);
790	    }
791	}
