793	/// Whether `value` is read directly by an operation outside this loop.
794	///
795	/// Passing it as an exit-edge operand is safe: that use belongs to the branch
796	/// inside the loop. The corresponding exit block argument is the value outside
797	/// code should read.
798	fn has_direct_outside_use(
799	    ctx: &Context,
800	    value: Value,
801	    loop_blocks: &FxHashSet<Ptr<BasicBlock>>,
802	) -> bool {
803	    value.uses(ctx).iter().any(|r#use| {
804	        r#use
805	            .user_op()
806	            .deref(ctx)
807	            .get_parent_block()
808	            .is_none_or(|block| !loop_blocks.contains(&block))
809	    })
810	}
811	
812	/// Check the live-out rule before cloning anything. With an early exit there is
813	/// no single "final" loop value, so every loop definition must leave through an
814	/// exit edge and an exit block argument. Without an early exit, header arguments
815	/// may still be replaced by their normal final values as the original path did.
816	fn liveouts_are_safe(ctx: &Context, shape: &LoopShape) -> bool {
817	    for &block in &shape.loop_blocks {
818	        for value in block.deref(ctx).arguments() {
819	            let replaceable_header_arg =
820	                !shape.has_early_exits && shape.header_args.contains(&value);
821	            if !replaceable_header_arg && has_direct_outside_use(ctx, value, &shape.loop_blocks) {
822	                return false;
823	            }
824	        }
825	        for op in block.deref(ctx).iter(ctx).collect::<Vec<_>>() {
826	            for value in op.deref(ctx).results() {
827	                if has_direct_outside_use(ctx, value, &shape.loop_blocks) {
828	                    return false;
829	                }
830	            }
831	        }
832	    }
833	    true
834	}
835	
836	/// Mathematical bounds representable by the IV type. Signless integers follow
837	/// the dialect's existing unsigned comparison convention. Unsigned 128-bit
838	/// values above `i128::MAX` are conservatively outside this analysis.
839	fn integer_value_bounds(ctx: &Context, ty: TypeHandle) -> Option<(i128, i128)> {
840	    let typed = TypedHandle::<IntegerType>::from_handle(ty, ctx).ok()?;
841	    let width = typed.deref(ctx).width();
842	    if width == 0 || width > 128 {
843	        return None;
844	    }
845	    match typed.deref(ctx).signedness() {
846	        Signedness::Signed if width == 128 => Some((i128::MIN, i128::MAX)),
847	        Signedness::Signed => {
848	            let half = 1i128.checked_shl(width - 1)?;
849	            Some((-half, half - 1))
850	        }
851	        Signedness::Unsigned | Signedness::Signless if width >= 127 => Some((0, i128::MAX)),
852	        Signedness::Unsigned | Signedness::Signless => Some((0, (1i128.checked_shl(width)? - 1))),
853	    }
854	}
855	
856	/// Full unrolling uses a mathematical recurrence. Prove that the fixed-width IV
857	/// reaches the same final value without wrapping; otherwise the original loop
858	/// may continue after the trip count this analysis computed.
859	fn full_iv_stays_in_range(ctx: &Context, shape: &LoopShape, trip: i128) -> bool {
860	    let Some((min, max)) = integer_value_bounds(ctx, shape.iv_type) else {
861	        return false;
862	    };
863	    let Some(delta) = trip.checked_mul(shape.iv_step) else {
864	        return false;
865	    };
866	    let Some(final_iv) = shape.iv_init.checked_add(delta) else {
867	        return false;
868	    };
869	    (min..=max).contains(&shape.iv_init) && (min..=max).contains(&final_iv)
870	}
871	
872	/// A grouped positive-IV span must be small enough to cross the type boundary
873	/// at most once. The runtime guard can then detect that crossing reliably.
874	fn partial_span_is_representable(ctx: &Context, ty: TypeHandle, span: i128) -> bool {
875	    let Some((_min, max)) = integer_value_bounds(ctx, ty) else {
876	        return false;
877	    };
878	    (0..=max).contains(&span)
879	}
