881	/// Fully unroll a loop whose iteration count is known at compile time, so no
882	/// loop is left at all. Works for any body shape the [`LoopShape`] checks allow,
883	/// including bodies with internal `if`/`else`/`match`, nested loops, early
884	/// exits, and multiple exit targets.
885	///
886	/// For a trip count `T`, it lays down `T` copies of the body, chained one into
887	/// the next: copy 0 entered from the preheader, copy `k`'s latch flowing into
888	/// copy `k+1`, and the last copy's latch flowing to the header's normal exit. In copy `k`
889	/// the counter is the literal `init + k*step`, and the other carried values are
890	/// threaded from each copy to the next. The original loop blocks become
891	/// unreachable and `simplify_cfg` deletes them.
892	///
893	/// Early exits are cloned with the body. Their outside targets stay unchanged,
894	/// while their edge operands are remapped to the current copy. An exit from copy
895	/// `k` therefore skips every later copy, just as `break` skips later iterations.
896	/// Values made in the body must leave through exit-edge operands and block
897	/// arguments. A small normalization handles direct outside uses of header-carried
898	/// values before cloning.
899	fn full_unroll(
900	    ctx: &mut Context,
901	    info: &LoopInfo,
902	    region: Ptr<Region>,
903	    id: usize,
904	    preheader: Ptr<BasicBlock>,
905	    rec: &induction::LoopRecurrences,
906	) -> Result<UnrollOutcome> {
907	    let s = match analyze_shape(ctx, info, region, id, preheader, rec, true) {
908	        Ok(s) => s,
909	        Err(why) => return Ok(UnrollOutcome::Skipped(why)),
910	    };
911	    let trip_count = match rec.trip_count {
912	        Some(t) => t,
913	        None => {
914	            return Ok(UnrollOutcome::Skipped(
915	                "full #[unroll] needs a compile-time-constant trip count; this loop's count is only known at runtime (use #[unroll(N)] for partial unrolling)".into(),
916	            ));
917	        }
918	    };
919	    if let Err(reason) = check_clone_budget(ctx, trip_count, &s.body_blocks_ordered) {
920	        return Ok(UnrollOutcome::Skipped(reason));
921	    }
922	    if !liveouts_are_safe(ctx, &s) {
923	        return Ok(UnrollOutcome::Skipped(
924	            "full unrolling requires values made in the loop body to leave through exit block arguments".into(),
925	        ));
926	    }
927	    let trip = i128::from(trip_count);
928	    if !full_iv_stays_in_range(ctx, &s, trip) {
929	        return Ok(UnrollOutcome::Skipped(
930	            "the loop counter may wrap before the computed full-unroll trip count is reached"
931	                .into(),
932	        ));
933	    }
934	
935	    // Precompute every literal before changing the CFG. Besides keeping all
936	    // arithmetic checked, this guarantees that an unsupported recurrence cannot
937	    // leave behind a partly unrolled loop.
938	    let copies = match usize::try_from(trip_count) {
939	        Ok(copies) => copies,
940	        Err(_) => {
941	            return Ok(UnrollOutcome::Skipped(
942	                "the full-unroll copy count does not fit this target's address space".into(),
943	            ));
944	        }
945	    };
946	    let Some(literal_count) = copies.checked_add(1) else {
947	        return Ok(UnrollOutcome::Skipped(
948	            "the full-unroll counter table is too large to allocate safely".into(),
949	        ));
950	    };
951	    let mut iv_literals = Vec::with_capacity(literal_count);
952	    for k in 0..=trip_count {
953	        let Some(delta) = i128::from(k).checked_mul(s.iv_step) else {
954	            return Ok(UnrollOutcome::Skipped(
955	                "the full-unroll counter arithmetic overflows the analysis range".into(),
956	            ));
957	        };
958	        let Some(value) = s.iv_init.checked_add(delta) else {
959	            return Ok(UnrollOutcome::Skipped(
960	                "the full-unroll counter arithmetic overflows the analysis range".into(),
961	            ));
962	        };
963	        iv_literals.push(value);
964	    }
965	
966	    // Carried values flowing into the next copy; start at the loop's initial
967	    // values. `prev_tail` is the branch we must point at the next copy (the
968	    // preheader first, then each copy's latch).
969	    let mut running: Vec<Value> = s.init_ops.clone();
970	    let mut prev_tail = s.preheader_term;
971	
972	    for &iv_literal in iv_literals.iter().take(copies) {
973	        // The counter in copy k is the literal init + k*step. Materialize it just
974	        // before the branch into this copy, so it dominates the copy.
975	        let iv_val = make_const(ctx, s.iv_type, iv_literal, prev_tail);
976	        let mut subst = running.clone();
977	        subst[s.iv_idx] = iv_val;
978	        let c = clone_one_copy(ctx, region, &s, &subst);
979	        rewire_goto(ctx, prev_tail, c.entry, &c.entry_args);
980	        prev_tail = c.latch_term;
981	        running = c.next_running;
982	    }
983	
984	    // The loop has finished: the counter's final value is the literal
985	    // init + T*step. Use it for any live-out reads of the counter.
986	    let final_iv = make_const(ctx, s.iv_type, iv_literals[copies], prev_tail);
987	    running[s.iv_idx] = final_iv;
988	
989	    // Branch the last copy to the exit, feeding the exit's own block arguments (if
990	    // any) the final carried values.
991	    let exit_args: Vec<Value> = s
992	        .normal_exit_ops
993	        .iter()
994	        .map(|&v| match s.header_args.iter().position(|&h| h == v) {
995	            Some(a) => running[a],
996	            None => v,
997	        })
998	        .collect();
999	    rewire_goto(ctx, prev_tail, s.normal_exit, &exit_args);
1000	
1001	    // The exit (and code after it) may also read the carried values *directly* by
1002	    // dominance (this IR is not loop-closed SSA, so a header block argument can be
1003	    // used outside the loop). The original header is now dead, so those reads must
1004	    // be repointed to the final unrolled values. Uses inside the loop are left
1005	    // alone; their blocks are unreachable and get deleted by `simplify_cfg`.
1006	    if !s.has_early_exits {
1007	        for (a, &replacement) in running.iter().enumerate().take(s.nargs) {
1008	            s.header_args[a].replace_some_uses_with(
1009	                ctx,
1010	                |ctx, u| match u.user_op().deref(ctx).get_parent_block() {
1011	                    Some(b) => !s.loop_blocks.contains(&b),
1012	                    None => true,
1013	                },
1014	                &replacement,
1015	            );
1016	        }
1017	    }
1018	
1019	    Ok(UnrollOutcome::Unrolled)
1020	}
