1022	/// Build an integer constant op (`mir.constant`) of type `ty` holding `value`,
1023	/// place it just before the op `before`, and hand back the value it produces.
1024	fn make_const(ctx: &mut Context, ty: TypeHandle, value: i128, before: Ptr<Operation>) -> Value {
1025	    let typed = TypedHandle::<IntegerType>::from_handle(ty, ctx).expect("IV is an integer type");
1026	    let width = typed.deref(ctx).width() as usize;
1027	    let apint = APInt::from_i128(value, NonZero::new(width).expect("non-zero width"));
1028	    let attr = IntegerAttr::new(typed, apint);
1029	    let op = Operation::new(
1030	        ctx,
1031	        MirConstantOp::get_concrete_op_info(),
1032	        vec![ty],
1033	        vec![],
1034	        vec![],
1035	        0,
1036	    );
1037	    MirConstantOp::new(op).set_attr_value(ctx, attr);
1038	    op.insert_before(ctx, before);
1039	    op.deref(ctx).get_result(0)
1040	}
1041	
1042	/// Partially unroll a loop: do `factor` iterations' worth of work per trip, and
1043	/// keep a small "remainder" loop for the iterations left over when the total
1044	/// doesn't divide evenly by `factor`. Works for any body shape the [`LoopShape`]
1045	/// checks allow (multi-block bodies included).
1046	///
1047	/// Unlike full unroll, this works even when the iteration count is only known at
1048	/// runtime. The original loop is reused as the **remainder loop**, running the
1049	/// last `trip % factor` iterations one at a time. In front of it we build a new
1050	/// **main loop** whose body is `factor` copies of the loop body chained
1051	/// together, advancing the counter by `factor*step` each trip. The main loop
1052	/// keeps going only while a whole group of `factor` more iterations still fits;
1053	/// once fewer than that remain, control falls into the remainder loop.
1054	///
1055	/// Multiple source latches are supported after normalization. An early `break`
1056	/// or another exit is not yet supported here: the main and remainder loops would
1057	/// need their path-specific exit values merged. Such a request warns and skips.
1058	/// Only counting-up loops (test `<` or `<=`, positive step) are handled.
1059	///
1060	/// What it produces (the loop was entered as `preheader -> header`):
1061	/// ```text
1062	///   preheader -> main_h(init...)
1063	///   main_h(acc, i):                       (i = counter, acc = carried values)
1064	///       if (i + (factor-1)*step) <pred> bound  -> copy0   (a full group fits)
1065	///       else                                   -> header  (run the remainder)
1066	///   copy0 .. copy(factor-1): the body, factor times, chained; the last copy's
1067	///       latch loops back to main_h with (acc', i + factor*step)
1068	///   header/.../latch: the original loop, now just the leftover tail
1069	/// ```
1070	fn partial_unroll(
1071	    ctx: &mut Context,
1072	    info: &LoopInfo,
1073	    region: Ptr<Region>,
1074	    id: usize,
1075	    preheader: Ptr<BasicBlock>,
1076	    rec: &induction::LoopRecurrences,
1077	    factor: u32,
1078	) -> Result<UnrollOutcome> {
1079	    if factor < 2 {
1080	        return Ok(UnrollOutcome::Skipped(format!(
1081	            "unroll factor {factor} is too small (need 2 or more)"
1082	        )));
1083	    }
1084	    let n = i128::from(factor);
1085	    let s = match analyze_shape(ctx, info, region, id, preheader, rec, false) {
1086	        Ok(s) => s,
1087	        Err(why) => return Ok(UnrollOutcome::Skipped(why)),
1088	    };
1089	    if let Err(reason) = check_clone_budget(ctx, u64::from(factor), &s.body_blocks_ordered) {
1090	        return Ok(UnrollOutcome::Skipped(reason));
1091	    }
1092	    let factor_usize = match usize::try_from(factor) {
1093	        Ok(factor) => factor,
1094	        Err(_) => {
1095	            return Ok(UnrollOutcome::Skipped(
1096	                "the partial-unroll factor does not fit this target's address space".into(),
1097	            ));
1098	        }
1099	    };
1100	    // Partial unroll needs an up-counting loop with a known bound value.
1101	    if s.iv_step <= 0 || !matches!(rec.continue_pred, Some(CmpPred::Lt) | Some(CmpPred::Le)) {
1102	        return Ok(UnrollOutcome::Skipped(
1103	            "partial #[unroll(N)] supports only up-counting loops (test < or <=, positive step) for now".into(),
1104	        ));
1105	    }
1106	    let Some(last_span) = (n - 1).checked_mul(s.iv_step) else {
1107	        return Ok(UnrollOutcome::Skipped(
1108	            "the partial-unroll counter step is too large to analyze safely".into(),
1109	        ));
1110	    };
1111	    let Some(group_step) = n.checked_mul(s.iv_step) else {
1112	        return Ok(UnrollOutcome::Skipped(
1113	            "the partial-unroll counter step is too large to analyze safely".into(),
1114	        ));
1115	    };
1116	    if !partial_span_is_representable(ctx, s.iv_type, last_span) {
1117	        return Ok(UnrollOutcome::Skipped(
1118	            "the partial-unroll group spans too much of the counter type to guard wraparound safely"
1119	                .into(),
1120	        ));
1121	    }
1122	    let pred = rec.continue_pred.unwrap();
1123	    let bound = match rec.bound_value {
1124	        Some(b) => b,
1125	        None => {
1126	            return Ok(UnrollOutcome::Skipped(
1127	                "partial #[unroll(N)] needs the loop bound as a value".into(),
1128	            ));
1129	        }
1130	    };
1131	    // The guard we build below, `i + (N-1)*step <pred> bound`, is only correct if
1132	    // `bound` is the same on every iteration. A constant bound is always fine (we
1133	    // re-materialize it in the main header below, so where its op sits does not
1134	    // matter). A non-constant bound that is a loop-carried header argument or is
1135	    // computed inside the loop can change within a group of N iterations, which
1136	    // would make the guard admit too many iterations (a miscompile), and would
1137	    // not dominate the new main header either. Bail loudly on those.
1138	    let bound_is_const = induction::const_i128(ctx, bound).is_some();
1139	    if !bound_is_const
1140	        && (s.header_args.contains(&bound) || defined_in_loop(ctx, bound, &s.loop_blocks))
1141	    {
1142	        return Ok(UnrollOutcome::Skipped(
1143	            "partial #[unroll(N)] needs a loop-invariant bound (the loop's limit must be the same on every iteration); this loop's limit changes inside the loop".into(),
1144	        ));
1145	    }
1146	
1147	    // Validate each per-copy offset before creating the main header or cloning
1148	    // any body block, so arithmetic failure is always a clean skip.
1149	    let mut copy_offsets = Vec::with_capacity(factor_usize);
1150	    for j in 0..factor {
1151	        let Some(offset) = i128::from(j).checked_mul(s.iv_step) else {
1152	            return Ok(UnrollOutcome::Skipped(
1153	                "the partial-unroll counter offset overflows the analysis range".into(),
1154	            ));
1155	        };
1156	        copy_offsets.push(offset);
1157	    }
1158	
1159	    let arg_types: Vec<TypeHandle> = s.header_args.iter().map(|a| a.get_type(ctx)).collect();
1160	    // The new main-loop header, taking the same carried values as the original.
1161	    let main_h = BasicBlock::new(ctx, None, arg_types);
1162	    main_h.insert_before(ctx, s.header);
1163	    let mh_args: Vec<Value> = (0..s.nargs)
1164	        .map(|i| main_h.deref(ctx).get_argument(i))
1165	        .collect();
1166	    let mh_iv = mh_args[s.iv_idx];
1167	
1168	    // Lay down `factor` copies of the body, threading non-IV carried values from
1169	    // one copy to the next. Give each copy an explicit `mh_iv + j*step` counter.
1170	    // This is semantically the same recurrence, and it keeps the affine relation
1171	    // visible even when a synthetic unified latch forwards its counter through a
1172	    // block argument.
1173	    let mut running: Vec<Value> = mh_args.clone();
1174	    let mut copies: Vec<CopyResult> = Vec::with_capacity(factor_usize);
1175	    for (j, offset) in copy_offsets.iter().copied().enumerate() {
1176	        let copy_iv = if j == 0 {
1177	            mh_iv
1178	        } else {
1179	            let offset_value = append_const(ctx, s.iv_type, offset, main_h);
1180	            append_add(ctx, s.iv_type, mh_iv, offset_value, main_h)
1181	        };
1182	        let mut subst = running.clone();
1183	        subst[s.iv_idx] = copy_iv;
1184	        let c = clone_one_copy(ctx, region, &s, &subst);
1185	        running = c.next_running.clone();
1186	        copies.push(c);
1187	    }
1188	    let next_offset = append_const(ctx, s.iv_type, group_step, main_h);
1189	    running[s.iv_idx] = append_add(ctx, s.iv_type, mh_iv, next_offset, main_h);
1190	
1191	    // Chain copy j's latch into copy j+1's entry; the last copy's latch loops
1192	    // back to main_h carrying `running` (counter now mh_iv + factor*step).
1193	    for j in 0..(factor_usize - 1) {
1194	        let next_entry = copies[j + 1].entry;
1195	        let next_args = copies[j + 1].entry_args.clone();
1196	        rewire_goto(ctx, copies[j].latch_term, next_entry, &next_args);
1197	    }
1198	    let last_latch = copies[factor_usize - 1].latch_term;
1199	    rewire_goto(ctx, last_latch, main_h, &running);
1200	
1201	    // The main-loop counter is mh_iv = init + (factor*step)*t, so it is always
1202	    // init plus a multiple of factor*step. That lets us replace counter-derived
1203	    // index ops -- `(counter +/- const) & mask` and `(counter +/- const) % 2^k`
1204	    // -- in the copies with literals (`fold_constant_index_in_copies`), the main
1205	    // payoff of unrolling. Scan every cloned copy block.
1206	    let copy_blocks: Vec<Ptr<BasicBlock>> = copies
1207	        .iter()
1208	        .flat_map(|c| c.blocks.iter().copied())
1209	        .collect();
1210	    fold_constant_index_in_copies(ctx, &copy_blocks, mh_iv, s.iv_init, group_step);
1211	
1212	    // main_h guard: stay in the main loop only while a whole group of `factor`
1213	    // iterations still fits. The last copy in a group uses counter
1214	    // mh_iv + (factor-1)*step, so the group fits when that still passes the test
1215	    // and did not wrap below mh_iv. True -> copy 0 (enter the main body); False
1216	    // -> the original header (the remainder loop), passing the current carried
1217	    // values. The remainder then preserves the source loop's exact wrap behavior.
1218	    // A constant bound may be defined inside the (original) loop, which does not
1219	    // dominate `main_h`; re-materialize it here. A non-constant bound was already
1220	    // checked to be defined outside the loop, so it dominates `main_h` as-is.
1221	    let guard_bound = match induction::const_i128(ctx, bound) {
1222	        Some(c) => append_const(ctx, bound.get_type(ctx), c, main_h),
1223	        None => bound,
1224	    };
1225	    let last_off = append_const(ctx, s.iv_type, last_span, main_h);
1226	    let last_iv = append_add(ctx, s.iv_type, mh_iv, last_off, main_h);
1227	    let within_bound = append_cmp(ctx, pred, last_iv, guard_bound, s.i1_type, main_h);
1228	    let no_wrap = append_cmp(ctx, CmpPred::Ge, last_iv, mh_iv, s.i1_type, main_h);
1229	    let cont = append_bitand(ctx, s.i1_type, within_bound, no_wrap, main_h);
1230	    let entry0 = copies[0].entry;
1231	    let entry0_args = copies[0].entry_args.clone();
1232	    let (flat, segs) =
1233	        MirCondBranchOp::compute_segment_sizes(vec![vec![cont], entry0_args, mh_args.clone()]);
1234	    let cbr = Operation::new(
1235	        ctx,
1236	        MirCondBranchOp::get_concrete_op_info(),
1237	        vec![],
1238	        flat,
1239	        vec![entry0, s.header],
1240	        0,
1241	    );
1242	    Operation::get_op::<MirCondBranchOp>(cbr, ctx)
1243	        .expect("MirCondBranchOp")
1244	        .set_operand_segment_sizes(ctx, segs);
1245	    cbr.insert_at_back(main_h, ctx);
1246	
1247	    // Finally, make the preheader branch into the new main loop instead of the
1248	    // original header, reusing the same initial values it already passed. The
1249	    // original loop stays in place and becomes the remainder.
1250	    rewire_goto(ctx, s.preheader_term, main_h, &s.init_ops);
1251	    Ok(UnrollOutcome::Unrolled)
1252	}
1253	
1254	/// If `v` is the counter `iv` plus or minus some constants (e.g. `iv`, `iv + 1`,
1255	/// `iv + 4 - 2`), return that net constant offset; `None` otherwise. So `iv + 1`
1256	/// gives `Some(1)` and `iv` gives `Some(0)`. The caller uses this to spot values
1257	/// that track the counter with a known fixed offset.
1258	fn affine_offset(ctx: &Context, v: Value, iv: Value) -> Option<i128> {
1259	    if v == iv {
1260	        return Some(0);
1261	    }
1262	    let def = v.defining_op()?;
1263	    if Operation::get_op::<MirAddOp>(def, ctx).is_some() {
1264	        let a = def.deref(ctx).get_operand(0);
1265	        let b = def.deref(ctx).get_operand(1);
1266	        if let (Some(o), Some(c)) = (affine_offset(ctx, a, iv), induction::const_i128(ctx, b)) {
1267	            return o.checked_add(c);
1268	        }
1269	        if let (Some(o), Some(c)) = (affine_offset(ctx, b, iv), induction::const_i128(ctx, a)) {
1270	            return o.checked_add(c);
1271	        }
1272	    } else if Operation::get_op::<MirSubOp>(def, ctx).is_some() {
1273	        let a = def.deref(ctx).get_operand(0);
1274	        let b = def.deref(ctx).get_operand(1);
1275	        if let (Some(o), Some(c)) = (affine_offset(ctx, a, iv), induction::const_i128(ctx, b)) {
1276	            return o.checked_sub(c);
1277	        }
1278	    }
1279	    None
1280	}
1281	
1282	/// Peephole: in each partial-unroll copy, replace a counter-derived index with
1283	/// the constant it always equals.
1284	///
1285	/// After unrolling by N, the main counter `iv` only takes values N apart:
1286	/// `init, init+N, init+2N, ...`. Copy `j` of the body uses `iv + j`. Two index
1287	/// shapes are then the same constant on every iteration, so we replace each with
1288	/// a literal (note `x & (2^k - 1)` and `x % 2^k` are the same operation):
1289	///
1290	/// ```text
1291	///   iv & MASK   (MASK = 2^k - 1)      keep the low k bits
1292	///   iv % M      (M a power of two)    same thing: x % 2^k == x & (2^k - 1)
1293	/// ```
1294	///
1295	/// Both read only the low k bits, and a multiple of N has *fixed* low k bits
1296	/// exactly when the window `2^k` divides the unroll step `N*step`. Example,
1297	/// N = 4, `(iv + j) & 3` (the gemm pipeline-stage index):
1298	///
1299	/// ```text
1300	///   iv = 0, 4, 8, 12, ...   all end in ...00, so:
1301	///     (iv + 0) & 3 = 0       (iv + 2) & 3 = 2
1302	///     (iv + 1) & 3 = 1       (iv + 3) & 3 = 3
1303	///   => each copy's stage index is a compile-time constant.
1304	/// ```
1305	///
1306	/// Fires only when ALL of these hold (otherwise the value genuinely changes each
1307	/// iteration, so there is nothing to fold and we skip):
1308	///
1309	/// - the op is `(iv +/- consts) & MASK` or `(iv +/- consts) % M`;
1310	/// - the window (`MASK + 1`, or `M`) is a power of two -- so it reads only low
1311	///   bits and is therefore immune to the type's wraparound;
1312	/// - that window divides the unroll step `N*step` -- so the low bits never move;
1313	/// - for `%`, the operand type is unsigned (signed `%` follows the dividend's
1314	///   sign, which breaks the equality with the masked low bits);
1315	/// - `M > 0` -- never fold `% 0` (rem-by-zero is a Rust panic).
1316	///
1317	/// Deliberately NOT handled: non-power-of-two `% M` (e.g. `% 3`). The congruence
1318	/// still holds on paper, but `%` by a non-power-of-two is not wraparound-safe:
1319	/// near the type's max the counter wraps by `2^width`, which is not a multiple
1320	/// of `M`, shifting the result. Documented gap, left for later.
1321	///
1322	/// Full unroll never needs this: there `iv` is a literal per copy, so ordinary
1323	/// constant folding already turns `i & 3` / `i % 3` into a number. The leftover
1324	/// dead `& MASK` / `% M` ops are removed by the unroll pass's later `dce`.
1325	///
1326	/// Parameters: `iv` is the counter; `init` its start; `step_jump` the unroll step
1327	/// (`N * original_step`), so `iv = init + step_jump * t` for iteration `t`.
1328	/// `blocks` are all the cloned copy blocks (one copy may span several blocks).
1329	fn fold_constant_index_in_copies(
1330	    ctx: &mut Context,
1331	    blocks: &[Ptr<BasicBlock>],
1332	    iv: Value,
1333	    init: i128,
1334	    step_jump: i128,
1335	) {
1336	    if step_jump <= 0 {
1337	        return;
1338	    }
1339	    for &block in blocks {
1340	        let ops: Vec<Ptr<Operation>> = block.deref(ctx).iter(ctx).collect();
1341	        for op in ops {
1342	            let Some((offset, window)) = counter_index_window(ctx, op, iv) else {
1343	                continue;
1344	            };
1345	            // Foldable only when the window is a power of two that divides the
1346	            // unroll step: then the counter's low bits never move, so the index
1347	            // is the same every iteration (and power-of-two makes it wrap-safe).
1348	            // The power-of-two check also rejects a non-low-bit `& C` (e.g.
1349	            // `x & 5` is not `x % 6`).
1350	            if window <= 0 || (window & (window - 1)) != 0 || step_jump % window != 0 {
1351	                continue;
1352	            }
1353	            let Some(base) = init.checked_add(offset) else {
1354	                continue;
1355	            };
1356	            let folded = base.rem_euclid(window);
1357	            let result = op.deref(ctx).get_result(0);
1358	            let ty = result.get_type(ctx);
1359	            let lit = make_const(ctx, ty, folded, op);
1360	            result.replace_all_uses_with(ctx, &lit);
1361	        }
1362	    }
1363	}
1364	
1365	/// If `op` is a counter-derived index we might fold -- `(iv +/- consts) & MASK`
1366	/// or `(iv +/- consts) % M` -- return `(offset, window)`, where `offset` is the
1367	/// counter's constant offset and `window` is `MASK + 1` (for `&`) or `M` (for
1368	/// `%`). The caller still checks that `window` is a power of two dividing the
1369	/// unroll step. Returns `None` for any other op.
1370	fn counter_index_window(ctx: &Context, op: Ptr<Operation>, iv: Value) -> Option<(i128, i128)> {
1371	    if Operation::get_op::<MirBitAndOp>(op, ctx).is_some() {
1372	        // `&` is commutative: either operand may be the counter.
1373	        let a = op.deref(ctx).get_operand(0);
1374	        let b = op.deref(ctx).get_operand(1);
1375	        let (offset, mask) = if let (Some(o), Some(m)) =
1376	            (affine_offset(ctx, a, iv), induction::const_i128(ctx, b))
1377	        {
1378	            (o, m)
1379	        } else if let (Some(o), Some(m)) =
1380	            (affine_offset(ctx, b, iv), induction::const_i128(ctx, a))
1381	        {
1382	            (o, m)
1383	        } else {
1384	            return None;
1385	        };
1386	        if mask < 0 {
1387	            return None;
1388	        }
1389	        // window = MASK + 1.
1390	        Some((offset, mask.checked_add(1)?))
1391	    } else if Operation::get_op::<MirRemOp>(op, ctx).is_some() {
1392	        // `%` is NOT commutative: only the dividend (operand 0) may be the
1393	        // counter, and only for unsigned types.
1394	        let dividend = op.deref(ctx).get_operand(0);
1395	        let divisor = op.deref(ctx).get_operand(1);
1396	        if !is_unsigned_int(ctx, dividend) {
1397	            return None;
1398	        }
1399	        let (Some(offset), Some(m)) = (
1400	            affine_offset(ctx, dividend, iv),
1401	            induction::const_i128(ctx, divisor),
1402	        ) else {
1403	            return None;
1404	        };
1405	        if m <= 0 {
1406	            return None;
1407	        }
1408	        // window = M.
1409	        Some((offset, m))
1410	    } else {
1411	        None
1412	    }
1413	}
1414	
1415	/// True if `v` has an unsigned (or signless) integer type. Keeps the `%` fold off
1416	/// signed remainders, whose result follows the dividend's sign rather than the
1417	/// masked low bits.
1418	fn is_unsigned_int(ctx: &Context, v: Value) -> bool {
1419	    let ty = v.get_type(ctx);
1420	    match TypedHandle::<IntegerType>::from_handle(ty, ctx) {
1421	        Ok(t) => t.deref(ctx).signedness() != Signedness::Signed,
1422	        Err(_) => false,
1423	    }
1424	}
1425	
1426	/// Build an integer constant `value` of type `ty`, add it as the last op of
1427	/// `block`, and return the value it produces. (Same as [`make_const`] but
1428	/// appends to a block instead of inserting before a given op.)
1429	fn append_const(ctx: &mut Context, ty: TypeHandle, value: i128, block: Ptr<BasicBlock>) -> Value {
1430	    let typed = TypedHandle::<IntegerType>::from_handle(ty, ctx).expect("integer type");
1431	    let width = typed.deref(ctx).width() as usize;
1432	    let apint = APInt::from_i128(value, NonZero::new(width).expect("non-zero width"));
1433	    let op = Operation::new(
1434	        ctx,
1435	        MirConstantOp::get_concrete_op_info(),
1436	        vec![ty],
1437	        vec![],
1438	        vec![],
1439	        0,
1440	    );
1441	    MirConstantOp::new(op).set_attr_value(ctx, IntegerAttr::new(typed, apint));
1442	    op.insert_at_back(block, ctx);
1443	    op.deref(ctx).get_result(0)
1444	}
1445	
1446	/// Build `a + b` (an integer `mir.add` of type `ty`), add it as the last op of
1447	/// `block`, and return its result value.
1448	fn append_add(
1449	    ctx: &mut Context,
1450	    ty: TypeHandle,
1451	    a: Value,
1452	    b: Value,
1453	    block: Ptr<BasicBlock>,
1454	) -> Value {
1455	    let op = Operation::new(
1456	        ctx,
1457	        MirAddOp::get_concrete_op_info(),
1458	        vec![ty],
1459	        vec![a, b],
1460	        vec![],
1461	        0,
1462	    );
1463	    op.insert_at_back(block, ctx);
1464	    op.deref(ctx).get_result(0)
1465	}
1466	
1467	/// Build boolean `a & b`, add it as the last op of `block`, and return its
1468	/// result. Both inputs and the result have `i1_type`.
1469	fn append_bitand(
1470	    ctx: &mut Context,
1471	    i1_type: TypeHandle,
1472	    a: Value,
1473	    b: Value,
1474	    block: Ptr<BasicBlock>,
1475	) -> Value {
1476	    let op = Operation::new(
1477	        ctx,
1478	        MirBitAndOp::get_concrete_op_info(),
1479	        vec![i1_type],
1480	        vec![a, b],
1481	        vec![],
1482	        0,
1483	    );
1484	    op.insert_at_back(block, ctx);
1485	    op.deref(ctx).get_result(0)
1486	}
1487	
1488	/// Build the comparison `a <pred> b` (a boolean, of type `i1_type`), add it as
1489	/// the last op of `block`, and return its result value.
1490	fn append_cmp(
1491	    ctx: &mut Context,
1492	    pred: CmpPred,
1493	    a: Value,
1494	    b: Value,
1495	    i1_type: TypeHandle,
1496	    block: Ptr<BasicBlock>,
1497	) -> Value {
1498	    let info = match pred {
1499	        CmpPred::Lt => MirLtOp::get_concrete_op_info(),
1500	        CmpPred::Le => MirLeOp::get_concrete_op_info(),
1501	        CmpPred::Gt => MirGtOp::get_concrete_op_info(),
1502	        CmpPred::Ge => MirGeOp::get_concrete_op_info(),
1503	    };
1504	    let op = Operation::new(ctx, info, vec![i1_type], vec![a, b], vec![], 0);
1505	    op.insert_at_back(block, ctx);
1506	    op.deref(ctx).get_result(0)
1507	}
1508	
1509	/// All function ops in the module (each `mir.func`).
1510	fn collect_functions(module: Ptr<Operation>, ctx: &Context) -> Vec<Ptr<Operation>> {
1511	    let mut out = Vec::new();
1512	    let module_region = module.deref(ctx).get_region(0);
1513	    let blocks: Vec<Ptr<BasicBlock>> = module_region.deref(ctx).iter(ctx).collect();
1514	    for block in blocks {
1515	        for op in block.deref(ctx).iter(ctx).collect::<Vec<_>>() {
1516	            if Operation::get_op::<MirFuncOp>(op, ctx).is_some() {
1517	                out.push(op);
1518	            }
1519	        }
1520	    }
1521	    out
1522	}
1523	
1524	/// Find the `mir.unroll_hint` ops in `region`, each with the block it sits in
1525	/// (used to locate the enclosing loop) and its requested factor (0 = full).
1526	fn collect_hints(
1527	    ctx: &Context,
1528	    region: Ptr<Region>,
1529	) -> Vec<(Ptr<Operation>, Ptr<BasicBlock>, u32)> {
1530	    let mut out = Vec::new();
1531	    let blocks: Vec<Ptr<BasicBlock>> = region.deref(ctx).iter(ctx).collect();
1532	    for block in blocks {
1533	        for op in block.deref(ctx).iter(ctx).collect::<Vec<_>>() {
1534	            if let Some(hint) = Operation::get_op::<MirUnrollHintOp>(op, ctx) {
1535	                out.push((op, block, hint.factor(ctx)));
1536	            }
1537	        }
1538	    }
1539	    out
1540	}
1541	
1542	#[cfg(test)]
1543	mod tests {
1544	    use super::check_growth_budget;
1545	
1546	    #[test]
1547	    fn growth_budget_counts_operations_not_only_blocks() {
1548	        let err = check_growth_budget(1_024, 1, 65).unwrap_err();
1549	        assert!(err.contains("65536 cloned operations"));
1550	        assert!(
1551	            check_growth_budget(1_024, 1, 64).is_ok(),
1552	            "the exact operation limit remains allowed"
1553	        );
1554	    }
1555	}
