352	        ToolchainPolicy::Explicit(toolchain) => GeneratedPtx {
353	            target: generate_ptx_with_toolchain(
354	                request.files.llvm_ir,
355	                request.files.ptx,
356	                request.debug_kind,
357	                request.backend,
358	                toolchain,
359	            )?,
360	            diagnostics: Vec::new(),
361	        },
362	    };
363	    if request.trace.verbose {
364	        request.trace.emit(format!(
365	            "✓ PTX written to {} (target: {})",
366	            request.files.ptx.display(),
367	            generated.target
368	        ));
369	    }
370	    Ok(ModulePipelineOutput {
371	        artifact_kind: ModuleArtifactKind::Ptx,
372	        target: generated.target,
373	        diagnostics: generated.diagnostics,
374	    })
375	}
376	
377	fn should_emit_nvvm_ir(policy: OutputPolicy, needs_libdevice: bool) -> bool {
378	    match policy {
379	        OutputPolicy::SelfContainedPtx => false,
380	        OutputPolicy::ExternalLinkAllowed { request_nvvm_ir } => request_nvvm_ir || needs_libdevice,
381	    }
382	}
