5	
6	//! Converts modern LLVM operations to the LLVM 7 forms accepted by
7	//! pre-Blackwell libNVVM.
8	//!
9	//! The pass runs after MIR-to-LLVM lowering. It preserves operation semantics
10	//! and reports an error when no equivalent legacy form is available.
11	
12	use std::num::NonZeroUsize;
13	
14	use llvm_export::{
15	    attributes::{
16	        FCmpPredicateAttr, FastmathFlagsAttr, ICmpPredicateAttr, IntegerOverflowFlagsAttr,
17	    },
18	    op_interfaces::{
19	        BinArithOp, CastOpInterface, CastOpWithNNegInterface, FastMathFlags,
20	        IntBinArithOpWithOverflowFlag,
21	    },
22	    ops as llvm, types as llvm_types,
23	};
24	use pliron::{
25	    builtin::{
26	        attributes::{BoolAttr, FPDoubleAttr, FPSingleAttr, IntegerAttr, TypeAttr},
27	        op_interfaces::{CallOpCallable, CallOpInterface, SymbolOpInterface},
28	        type_interfaces::FunctionTypeInterface,
29	        types::{FP16Type, FP32Type, FP64Type, IntegerType, Signedness},
30	    },
31	    context::{Context, Ptr},
32	    identifier::Identifier,
33	    linked_list::ContainsLinkedList,
34	    location::Located,
35	    op::Op,
36	    operation::Operation,
37	    result::Result,
38	    r#type::{TypeHandle, Typed},
39	    utils::apint::APInt,
40	    value::Value,
41	};
42	
43	use crate::helpers;
44	
45	const NNEG_ATTR: &str = "llvm_nneg_flag";
46	
47	/// Rewrite a lowered LLVM module to the LLVM 7 subset used by legacy NVVM IR.
48	///
49	/// Atomic and fence operations that cuda-oxide has not yet legalized return an
50	/// error instead of being emitted with unverified semantics.
51	pub(crate) fn legalize_for_legacy_nvvm(ctx: &mut Context, module: Ptr<Operation>) -> Result<()> {
52	    let mut ops = Vec::new();
53	    collect_ops(ctx, module, &mut ops);
54	
55	    // Validate the complete module before changing it. Some unsupported
56	    // ordering and scope settings are otherwise ignored by libNVVM.
57	    for &op in &ops {
58	        reject_nonportable_f16_types(ctx, op)?;
59	        reject_unsupported_op(ctx, op)?;
60	        validate_rewrite_candidate(ctx, op)?;
61	    }
62	
63	    let mut obsolete_declarations = Vec::new();
64	    for op in ops {
65	        remove_nneg(ctx, op);
66	
67	        if Operation::get_op::<llvm::FNegOp>(op, ctx).is_some() {
68	            rewrite_fneg(ctx, op)?;
69	            continue;
70	        }
71	
72	        let Some(call) = Operation::get_op::<llvm::CallOp>(op, ctx) else {
73	            continue;
74	        };
75	        let CallOpCallable::Direct(callee) = call.callee(ctx) else {
76	            continue;
77	        };
78	        let name = callee.to_string();
79	
80	        if parse_integer_sat_name(&name).is_some() {
81	            rewrite_integer_sat(ctx, op, &name)?;
82	            obsolete_declarations.push(name);
83	        } else if parse_float_to_int_sat_name(&name).is_some() {
84	            rewrite_float_to_int_sat(ctx, op, &name)?;
85	            obsolete_declarations.push(name);
86	        } else if legacy_bit_rewrite(&name).is_some() {
87	            rewrite_legacy_bit_intrinsic(ctx, op, &name)?;
88	            obsolete_declarations.push(name);
89	        } else if shuffle_mode(&name).is_some() {
90	            rewrite_shuffle(ctx, op, &name)?;
91	            obsolete_declarations.push(name);
92	        } else if vote_mode(&name).is_some() {
93	            rewrite_vote(ctx, op, &name)?;
94	            obsolete_declarations.push(name);
95	        } else if let Some(legacy_name) = legacy_memory_intrinsic_name(&name) {
96	            rewrite_renamed_call(ctx, op, &legacy_name)?;
97	            obsolete_declarations.push(name);
98	        }
99	    }
100	
101	    remove_obsolete_declarations(ctx, module, &obsolete_declarations);
102	    verify_legacy_subset(ctx, module)
103	}
104	
105	/// Rewrite bit-manipulation intrinsics whose integer widths NVVM rejects in
106	/// both textual dialects.
107	///
108	/// Unlike [`legalize_for_legacy_nvvm`], this leaves modern operations, flags,
109	/// f16, atomics, and intrinsic signatures unchanged. Blackwell and newer
110	/// targets accept those forms, but NVVM bit intrinsics still stop at i64.
111	pub(crate) fn legalize_nvvm_bit_intrinsics(
112	    ctx: &mut Context,
113	    module: Ptr<Operation>,
114	) -> Result<()> {
115	    let mut ops = Vec::new();
116	    collect_ops(ctx, module, &mut ops);
117	
118	    // Validate every candidate before changing the module.
119	    for &op in &ops {
120	        let Some(call) = Operation::get_op::<llvm::CallOp>(op, ctx) else {
121	            continue;
122	        };
123	        let CallOpCallable::Direct(callee) = call.callee(ctx) else {
124	            continue;
125	        };
126	        let name = callee.to_string();
127	        if legacy_bit_rewrite(&name).is_some() {
128	            validate_legacy_bit_call(ctx, op, &name)?;
129	        }
130	    }
131	
132	    let mut obsolete_declarations = Vec::new();
133	    for op in ops {
134	        let Some(call) = Operation::get_op::<llvm::CallOp>(op, ctx) else {
135	            continue;
136	        };
137	        let CallOpCallable::Direct(callee) = call.callee(ctx) else {
138	            continue;
139	        };
140	        let name = callee.to_string();
141	        if legacy_bit_rewrite(&name).is_some() {
142	            rewrite_legacy_bit_intrinsic(ctx, op, &name)?;
143	            obsolete_declarations.push(name);
144	        }
145	    }
146	
147	    remove_obsolete_declarations(ctx, module, &obsolete_declarations);
148	    let mut rewritten_ops = Vec::new();
149	    collect_ops(ctx, module, &mut rewritten_ops);
150	    for op in rewritten_ops {
151	        let Some(call) = Operation::get_op::<llvm::CallOp>(op, ctx) else {
152	            continue;
153	        };
154	        let CallOpCallable::Direct(callee) = call.callee(ctx) else {
155	            continue;
156	        };
157	        if legacy_bit_rewrite(&callee.to_string()).is_some() {
158	            return pliron::input_err!(
159	                op.deref(ctx).loc(),
160	                "NVVM bit-intrinsic legalization left unsupported call @{callee} behind"
161	            );
162	        }
163	    }
164	    Ok(())
165	}
