167	/// CUDA 12's LLVM 7 NVVM dialect does not support the scalar `half` type.
168	///
169	/// This checks operands, results, function and global signatures, block
170	/// arguments, aggregate elements, and operation type attributes. Named
171	/// recursive structs are guarded by the `seen` set.
172	fn reject_nonportable_f16_types(ctx: &Context, op: Ptr<Operation>) -> Result<()> {
173	    let has_half = op
174	        .deref(ctx)
175	        .operands()
176	        .any(|value| type_contains_f16(ctx, value.get_type(ctx), &mut Vec::new()))
177	        || op
178	            .deref(ctx)
179	            .results()
180	            .any(|value| type_contains_f16(ctx, value.get_type(ctx), &mut Vec::new()))
181	        || op.deref(ctx).attributes.0.values().any(|attr| {
182	            attr.downcast_ref::<TypeAttr>()
183	                .is_some_and(|ty| type_contains_f16(ctx, ty.get_type(ctx), &mut Vec::new()))
184	        })
185	        || op.deref(ctx).regions().any(|region| {
186	            region.deref(ctx).iter(ctx).any(|block| {
187	                block
188	                    .deref(ctx)
189	                    .arguments()
190	                    .any(|argument| type_contains_f16(ctx, argument.get_type(ctx), &mut Vec::new()))
191	            })
192	        })
193	        || Operation::get_op::<llvm::FuncOp>(op, ctx)
194	            .is_some_and(|func| type_contains_f16(ctx, func.get_type(ctx).into(), &mut Vec::new()))
195	        || Operation::get_op::<llvm::GlobalOp>(op, ctx)
196	            .is_some_and(|global| type_contains_f16(ctx, global.get_type(ctx), &mut Vec::new()));
197	
198	    if has_half {
199	        return pliron::input_err!(
200	            op.deref(ctx).loc(),
201	            "legacy NVVM IR cannot contain scalar f16 because cuda-oxide supports the CUDA 12 LLVM 7 dialect; use f32/f64 or the modern NVVM/PTX path"
202	        );
203	    }
204	    Ok(())
205	}
206	
207	fn type_contains_f16(ctx: &Context, ty: TypeHandle, seen: &mut Vec<TypeHandle>) -> bool {
208	    if ty.deref(ctx).is::<FP16Type>() {
209	        return true;
210	    }
211	    if seen.contains(&ty) {
212	        return false;
213	    }
214	    seen.push(ty);
215	
216	    let ty_ref = ty.deref(ctx);
217	    if let Some(struct_ty) = ty_ref.downcast_ref::<llvm_types::StructType>() {
218	        !struct_ty.is_opaque()
219	            && struct_ty
220	                .fields()
221	                .any(|field| type_contains_f16(ctx, field, seen))
222	    } else if let Some(array_ty) = ty_ref.downcast_ref::<llvm_types::ArrayType>() {
223	        type_contains_f16(ctx, array_ty.elem_type(), seen)
224	    } else if let Some(vector_ty) = ty_ref.downcast_ref::<llvm_types::VectorType>() {
225	        type_contains_f16(ctx, vector_ty.elem_type(), seen)
226	    } else if let Some(func_ty) = ty_ref.downcast_ref::<llvm_types::FuncType>() {
227	        type_contains_f16(ctx, func_ty.result_type(), seen)
228	            || func_ty
229	                .arg_types()
230	                .into_iter()
231	                .any(|arg| type_contains_f16(ctx, arg, seen))
232	    } else {
233	        false
234	    }
235	}
