237	fn collect_ops(ctx: &Context, root: Ptr<Operation>, out: &mut Vec<Ptr<Operation>>) {
238	    out.push(root);
239	    let regions: Vec<_> = root.deref(ctx).regions().collect();
240	    for region in regions {
241	        let blocks: Vec<_> = region.deref(ctx).iter(ctx).collect();
242	        for block in blocks {
243	            let children: Vec<_> = block.deref(ctx).iter(ctx).collect();
244	            for child in children {
245	                collect_ops(ctx, child, out);
246	            }
247	        }
248	    }
249	}
