251	fn reject_unsupported_op(ctx: &Context, op: Ptr<Operation>) -> Result<()> {
252	    let reason = if Operation::get_op::<llvm::AtomicLoadOp>(op, ctx).is_some() {
253	        Some("atomic loads")
254	    } else if Operation::get_op::<llvm::AtomicStoreOp>(op, ctx).is_some() {
255	        Some("atomic stores")
256	    } else if Operation::get_op::<llvm::AtomicRmwOp>(op, ctx).is_some() {
257	        Some("atomic read-modify-write operations")
258	    } else if Operation::get_op::<llvm::AtomicCmpxchgOp>(op, ctx).is_some() {
259	        Some("atomic compare-exchange operations")
260	    } else if Operation::get_op::<llvm::FenceOp>(op, ctx).is_some() {
261	        Some("LLVM fences")
262	    } else if Operation::get_op::<llvm::DebugValueOp>(op, ctx).is_some() {
263	        Some("LLVM debug-value records")
264	    } else {
265	        None
266	    };
267	
268	    if let Some(reason) = reason {
269	        return pliron::input_err!(
270	            op.deref(ctx).loc(),
271	            "cuda-oxide has not yet legalized {reason} for legacy NVVM IR; use ordinary PTX output or a Blackwell NVVM target"
272	        );
273	    }
274	    Ok(())
275	}
