277	fn validate_rewrite_candidate(ctx: &Context, op: Ptr<Operation>) -> Result<()> {
278	    if Operation::get_op::<llvm::FNegOp>(op, ctx).is_some() {
279	        let ty = op.deref(ctx).get_operand(0).get_type(ctx);
280	        if !matches!(float_width(ctx, ty), Some(32) | Some(64)) {
281	            return pliron::input_err!(
282	                op.deref(ctx).loc(),
283	                "legacy NVVM fneg legalization supports only scalar f32 and f64; scalar f16 is not portable to the supported CUDA 12 legacy dialect"
284	            );
285	        }
286	    }
287	
288	    let Some(call) = Operation::get_op::<llvm::CallOp>(op, ctx) else {
289	        return Ok(());
290	    };
291	    let CallOpCallable::Direct(callee) = call.callee(ctx) else {
292	        return Ok(());
293	    };
294	    let name = callee.to_string();
295	    if parse_integer_sat_name(&name).is_some() {
296	        validate_integer_sat_call(ctx, op, &name)?;
297	    } else if parse_float_to_int_sat_name(&name).is_some() {
298	        validate_float_to_int_sat_call(ctx, op, &name)?;
299	    } else if legacy_bit_rewrite(&name).is_some() {
300	        validate_legacy_bit_call(ctx, op, &name)?;
301	    } else if shuffle_mode(&name).is_some() {
302	        validate_shuffle_call(ctx, op, &name)?;
303	    } else if vote_mode(&name).is_some() {
304	        validate_vote_call(ctx, op, &name)?;
305	    }
306	    Ok(())
307	}
