309	fn remove_nneg(ctx: &mut Context, op: Ptr<Operation>) {
310	    let key: Identifier = NNEG_ATTR
311	        .try_into()
312	        .expect("static attribute name is valid");
313	    // `ZExtOp` and `UIToFPOp` implement pliron-LLVM's NNegFlag interface,
314	    // whose verifier requires the attribute to exist even when it is false.
315	    // LLVM 7 cannot parse the textual `nneg` keyword, so clear the semantic
316	    // bit while retaining the dialect invariant; the exporter omits false.
317	    if op.deref(ctx).attributes.0.contains_key(&key) {
318	        op.deref_mut(ctx).attributes.set(key, BoolAttr::new(false));
319	    }
320	}
