400	fn rewrite_fneg(ctx: &mut Context, op: Ptr<Operation>) -> Result<()> {
401	    let value = op.deref(ctx).get_operand(0);
402	    let float_ty = value.get_type(ctx);
403	    let width = float_width(ctx, float_ty).ok_or_else(|| {
404	        pliron::input_error!(
405	            op.deref(ctx).loc(),
406	            "legacy fneg legalization supports only scalar f32 and f64"
407	        )
408	    })?;
409	    let int_ty: TypeHandle = IntegerType::get(ctx, width, Signedness::Signless).into();
410	
411	    // IEEE negation is exactly a sign-bit toggle, including for NaNs and
412	    // signed zero.  This is stronger than `0.0 - x`, which changes NaNs and
413	    // mishandles +0.0.
414	    let as_int_op = llvm::BitcastOp::new(ctx, value, int_ty).get_operation();
415	    let as_int = insert_before(ctx, op, as_int_op);
416	    let sign_mask = integer_const(ctx, op, width, 1_u128 << (width - 1));
417	    let toggled_op = llvm::XorOp::new(ctx, as_int, sign_mask).get_operation();
418	    let toggled = insert_before(ctx, op, toggled_op);
419	    let result_op = llvm::BitcastOp::new(ctx, toggled, float_ty).get_operation();
420	    let result = insert_before(ctx, op, result_op);
421	    replace_one_result(ctx, op, result)
422	}
