424	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
425	enum IntegerSatKind {
426	    SignedAdd,
427	    SignedSub,
428	    UnsignedAdd,
429	    UnsignedSub,
430	}
431	
432	fn parse_integer_sat_name(name: &str) -> Option<(IntegerSatKind, u32)> {
433	    let (kind, width) = if let Some(rest) = name.strip_prefix("llvm_sadd_sat_i") {
434	        (IntegerSatKind::SignedAdd, rest)
435	    } else if let Some(rest) = name.strip_prefix("llvm_ssub_sat_i") {
436	        (IntegerSatKind::SignedSub, rest)
437	    } else if let Some(rest) = name.strip_prefix("llvm_uadd_sat_i") {
438	        (IntegerSatKind::UnsignedAdd, rest)
439	    } else if let Some(rest) = name.strip_prefix("llvm_usub_sat_i") {
440	        (IntegerSatKind::UnsignedSub, rest)
441	    } else {
442	        return None;
443	    };
444	    let width = width.parse().ok()?;
445	    (width > 0 && width <= 128).then_some((kind, width))
446	}
447	
448	fn validate_integer_sat_call(ctx: &Context, op: Ptr<Operation>, name: &str) -> Result<()> {
449	    let (_, expected_width) = parse_integer_sat_name(name).expect("validated intrinsic name");
450	    let operands: Vec<_> = op.deref(ctx).operands().collect();
451	    if operands.len() != 2 || op.deref(ctx).get_num_results() != 1 {
452	        return pliron::input_err!(
453	            op.deref(ctx).loc(),
454	            "{name} must have two operands and one result"
455	        );
456	    }
457	    let result_ty = op.deref(ctx).get_result(0).get_type(ctx);
458	    let width = scalar_integer_width(ctx, result_ty);
459	    if width != Some(expected_width) || operands.iter().any(|v| v.get_type(ctx) != result_ty) {
460	        return pliron::input_err!(
461	            op.deref(ctx).loc(),
462	            "{name} has a signature inconsistent with its overload suffix"
463	        );
464	    }
465	    Ok(())
466	}
467	
468	fn rewrite_integer_sat(ctx: &mut Context, op: Ptr<Operation>, name: &str) -> Result<()> {
469	    let (kind, width) = parse_integer_sat_name(name).expect("validated intrinsic name");
470	    let operands: Vec<_> = op.deref(ctx).operands().collect();
471	    let (lhs, rhs) = (operands[0], operands[1]);
472	    let flags = IntegerOverflowFlagsAttr::default();
473	    let arithmetic = match kind {
474	        IntegerSatKind::SignedAdd | IntegerSatKind::UnsignedAdd => {
475	            llvm::AddOp::new_with_overflow_flag(ctx, lhs, rhs, flags).get_operation()
476	        }
477	        IntegerSatKind::SignedSub | IntegerSatKind::UnsignedSub => {
478	            llvm::SubOp::new_with_overflow_flag(ctx, lhs, rhs, flags).get_operation()
479	        }
480	    };
481	    let value = insert_before(ctx, op, arithmetic);
482	
483	    let result = match kind {
484	        IntegerSatKind::UnsignedAdd => {
485	            let overflow = icmp(ctx, op, ICmpPredicateAttr::ULT, value, lhs);
486	            let max = integer_const(ctx, op, width, mask_for_width(width));
487	            select(ctx, op, overflow, max, value)
488	        }
489	        IntegerSatKind::UnsignedSub => {
490	            let underflow = icmp(ctx, op, ICmpPredicateAttr::ULT, lhs, rhs);
491	            let zero = integer_const(ctx, op, width, 0);
492	            select(ctx, op, underflow, zero, value)
493	        }
494	        IntegerSatKind::SignedAdd | IntegerSatKind::SignedSub => {
495	            let zero = integer_const(ctx, op, width, 0);
496	            let lhs_negative = icmp(ctx, op, ICmpPredicateAttr::SLT, lhs, zero);
497	            let rhs_negative = icmp(ctx, op, ICmpPredicateAttr::SLT, rhs, zero);
498	            let result_negative = icmp(ctx, op, ICmpPredicateAttr::SLT, value, zero);
499	            let lhs_rhs_relation = icmp(
500	                ctx,
501	                op,
502	                if kind == IntegerSatKind::SignedAdd {
503	                    ICmpPredicateAttr::EQ
504	                } else {
505	                    ICmpPredicateAttr::NE
506	                },
507	                lhs_negative,
508	                rhs_negative,
509	            );
510	            let sign_changed = icmp(
511	                ctx,
512	                op,
513	                ICmpPredicateAttr::NE,
514	                lhs_negative,
515	                result_negative,
516	            );
517	            let overflow = bool_binop::<llvm::AndOp>(ctx, op, lhs_rhs_relation, sign_changed);
518	            let min = integer_const(ctx, op, width, 1_u128 << (width - 1));
519	            let max = integer_const(ctx, op, width, (1_u128 << (width - 1)) - 1);
520	            let clamp = select(ctx, op, lhs_negative, min, max);
521	            select(ctx, op, overflow, clamp, value)
522	        }
523	    };
524	    replace_one_result(ctx, op, result)
525	}
