535	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
536	enum LegacyBitRewrite {
537	    InvalidBswapI8,
538	    FunnelLeftI128,
539	    FunnelRightI128,
540	    BswapI128,
541	    BitreverseI128,
542	    CtpopI128,
543	    CtlzI128,
544	    CttzI128,
545	}
546	
547	/// NVVM only accepts bit-manipulation intrinsics through i64. Rust exposes the
548	/// same operations for i128, so split them into exact i64 operations before
549	/// handing the module to libNVVM. `llvm.bswap.i8` is not valid LLVM IR at all;
550	/// recognize it only so malformed input fails during validation rather than in
551	/// the textual LLVM verifier. Rust's `u8::swap_bytes` is lowered to an identity
552	/// before this pass.
553	fn legacy_bit_rewrite(name: &str) -> Option<LegacyBitRewrite> {
554	    match name {
555	        "llvm_bswap_i8" => Some(LegacyBitRewrite::InvalidBswapI8),
556	        "llvm_fshl_i128" => Some(LegacyBitRewrite::FunnelLeftI128),
557	        "llvm_fshr_i128" => Some(LegacyBitRewrite::FunnelRightI128),
558	        "llvm_bswap_i128" => Some(LegacyBitRewrite::BswapI128),
559	        "llvm_bitreverse_i128" => Some(LegacyBitRewrite::BitreverseI128),
560	        "llvm_ctpop_i128" => Some(LegacyBitRewrite::CtpopI128),
561	        "llvm_ctlz_i128" => Some(LegacyBitRewrite::CtlzI128),
562	        "llvm_cttz_i128" => Some(LegacyBitRewrite::CttzI128),
563	        _ => None,
564	    }
565	}
566	
567	fn validate_legacy_bit_call(ctx: &Context, op: Ptr<Operation>, name: &str) -> Result<()> {
568	    let kind = legacy_bit_rewrite(name).expect("validated legacy bit intrinsic name");
569	    let operands: Vec<_> = op.deref(ctx).operands().collect();
570	    if op.deref(ctx).get_num_results() != 1 {
571	        return pliron::input_err!(
572	            op.deref(ctx).loc(),
573	            "{name} must produce exactly one result"
574	        );
575	    }
576	    let result_ty = op.deref(ctx).get_result(0).get_type(ctx);
577	    let i1_ty: TypeHandle = IntegerType::get(ctx, 1, Signedness::Signless).into();
578	    let expected_width = if kind == LegacyBitRewrite::InvalidBswapI8 {
579	        8
580	    } else {
581	        128
582	    };
583	    if scalar_integer_width(ctx, result_ty) != Some(expected_width) {
584	        return pliron::input_err!(
585	            op.deref(ctx).loc(),
586	            "{name} result type does not match its overload suffix"
587	        );
588	    }
589	
590	    let valid = match kind {
591	        LegacyBitRewrite::FunnelLeftI128 | LegacyBitRewrite::FunnelRightI128 => {
592	            operands.len() == 3
593	                && operands
594	                    .iter()
595	                    .all(|value| value.get_type(ctx) == result_ty)
596	        }
597	        LegacyBitRewrite::CtlzI128 | LegacyBitRewrite::CttzI128 => {
598	            operands.len() == 2
599	                && operands[0].get_type(ctx) == result_ty
600	                && operands[1].get_type(ctx) == i1_ty
601	        }
602	        _ => operands.len() == 1 && operands[0].get_type(ctx) == result_ty,
603	    };
604	    if !valid {
605	        return pliron::input_err!(
606	            op.deref(ctx).loc(),
607	            "{name} has a signature inconsistent with its overload suffix"
608	        );
609	    }
610	
611	    if kind == LegacyBitRewrite::InvalidBswapI8 {
612	        return pliron::input_err!(
613	            op.deref(ctx).loc(),
614	            "{name} is not a valid LLVM intrinsic: byte-swap widths must be a multiple of 16 bits"
615	        );
616	    }
617	
618	    if matches!(
619	        kind,
620	        LegacyBitRewrite::CtlzI128 | LegacyBitRewrite::CttzI128
621	    ) && literal_i1_constant(ctx, operands[1]).is_none()
622	    {
623	        return pliron::input_err!(
624	            op.deref(ctx).loc(),
625	            "{name} is_zero_poison flag must be an immediate i1 constant (0 or 1)"
626	        );
627	    }
628	    Ok(())
629	}
630	
631	fn literal_i1_constant(ctx: &Context, value: Value) -> Option<bool> {
632	    let defining_op = value.defining_op()?;
633	    let constant = Operation::get_op::<llvm::ConstantOp>(defining_op, ctx)?;
634	    let attr = constant.get_value(ctx);
635	    let integer = attr.downcast_ref::<IntegerAttr>()?;
636	    match integer.value().to_u64() {
637	        0 => Some(false),
638	        1 => Some(true),
639	        _ => None,
640	    }
641	}
642	
643	fn split_i128(ctx: &mut Context, anchor: Ptr<Operation>, value: Value) -> (Value, Value) {
644	    let i64_ty: TypeHandle = IntegerType::get(ctx, 64, Signedness::Signless).into();
645	    let low_op = llvm::TruncOp::new(ctx, value, i64_ty).get_operation();
646	    let low = insert_before(ctx, anchor, low_op);
647	    let shift = integer_const(ctx, anchor, 128, 64);
648	    let shifted_op = llvm::LShrOp::new(ctx, value, shift).get_operation();
649	    let shifted = insert_before(ctx, anchor, shifted_op);
650	    let high_op = llvm::TruncOp::new(ctx, shifted, i64_ty).get_operation();
651	    let high = insert_before(ctx, anchor, high_op);
652	    (low, high)
653	}
