661	fn call_i64_intrinsic(
662	    ctx: &mut Context,
663	    anchor: Ptr<Operation>,
664	    name: &str,
665	    args: Vec<Value>,
666	) -> Result<Value> {
667	    let i64_ty: TypeHandle = IntegerType::get(ctx, 64, Signedness::Signless).into();
668	    let param_types = args.iter().map(|value| value.get_type(ctx)).collect();
669	    let func_ty = llvm_types::FuncType::get(ctx, i64_ty, param_types, false);
670	    let parent_block = anchor.deref(ctx).get_parent_block().ok_or_else(|| {
671	        pliron::input_error!(
672	            anchor.deref(ctx).loc(),
673	            "intrinsic call has no parent block"
674	        )
675	    })?;
676	    helpers::ensure_intrinsic_declared(ctx, parent_block, name, func_ty)
677	        .map_err(|error| pliron::input_error!(anchor.deref(ctx).loc(), "{error}"))?;
678	    let call = llvm::CallOp::new(
679	        ctx,
680	        CallOpCallable::Direct(name.try_into().map_err(|error| {
681	            pliron::input_error!(anchor.deref(ctx).loc(), "invalid intrinsic name: {error}")
682	        })?),
683	        func_ty,
684	        args,
685	    );
686	    Ok(insert_before(ctx, anchor, call.get_operation()))
687	}
