689	fn combine_reversed_i64_halves(
690	    ctx: &mut Context,
691	    anchor: Ptr<Operation>,
692	    low: Value,
693	    high: Value,
694	) -> Value {
695	    // Reversing bytes or bits across the complete i128 swaps the transformed
696	    // halves: transformed(low) becomes the high half of the result.
697	    let low = zext_to_i128(ctx, anchor, low);
698	    let high = zext_to_i128(ctx, anchor, high);
699	    let shift = integer_const(ctx, anchor, 128, 64);
700	    let low_as_high = shl(ctx, anchor, low, shift);
701	    let combined = llvm::OrOp::new(ctx, low_as_high, high).get_operation();
702	    insert_before(ctx, anchor, combined)
703	}
