705	fn rewrite_legacy_bit_intrinsic(ctx: &mut Context, op: Ptr<Operation>, name: &str) -> Result<()> {
706	    let kind = legacy_bit_rewrite(name).expect("validated legacy bit intrinsic name");
707	    let operands: Vec<_> = op.deref(ctx).operands().collect();
708	    let result = match kind {
709	        LegacyBitRewrite::InvalidBswapI8 => {
710	            return pliron::input_err!(
711	                op.deref(ctx).loc(),
712	                "{name} reached rewriting despite being rejected during validation"
713	            );
714	        }
715	        LegacyBitRewrite::FunnelLeftI128 | LegacyBitRewrite::FunnelRightI128 => {
716	            let mask = integer_const(ctx, op, 128, 127);
717	            let shift = bool_binop::<llvm::AndOp>(ctx, op, operands[2], mask);
718	            let zero = integer_const(ctx, op, 128, 0);
719	            let negative_shift_op = llvm::SubOp::new_with_overflow_flag(
720	                ctx,
721	                zero,
722	                shift,
723	                IntegerOverflowFlagsAttr::default(),
724	            )
725	            .get_operation();
726	            let negative_shift = insert_before(ctx, op, negative_shift_op);
727	            let reverse_shift = bool_binop::<llvm::AndOp>(ctx, op, negative_shift, mask);
728	            let is_zero = icmp(ctx, op, ICmpPredicateAttr::EQ, shift, zero);
729	            let (left, right, zero_result) = if kind == LegacyBitRewrite::FunnelLeftI128 {
730	                (operands[0], operands[1], operands[0])
731	            } else {
732	                (operands[0], operands[1], operands[1])
733	            };
734	            let left_shift = if kind == LegacyBitRewrite::FunnelLeftI128 {
735	                shift
736	            } else {
737	                reverse_shift
738	            };
739	            let right_shift = if kind == LegacyBitRewrite::FunnelLeftI128 {
740	                reverse_shift
741	            } else {
742	                shift
743	            };
744	            let left = shl(ctx, op, left, left_shift);
745	            let right_op = llvm::LShrOp::new(ctx, right, right_shift).get_operation();
746	            let right = insert_before(ctx, op, right_op);
747	            let combined_op = llvm::OrOp::new(ctx, left, right).get_operation();
748	            let combined = insert_before(ctx, op, combined_op);
749	            select(ctx, op, is_zero, zero_result, combined)
750	        }
751	        LegacyBitRewrite::BswapI128 | LegacyBitRewrite::BitreverseI128 => {
752	            let (low, high) = split_i128(ctx, op, operands[0]);
753	            let intrinsic = if kind == LegacyBitRewrite::BswapI128 {
754	                "llvm_bswap_i64"
755	            } else {
756	                "llvm_bitreverse_i64"
757	            };
758	            let low = call_i64_intrinsic(ctx, op, intrinsic, vec![low])?;
759	            let high = call_i64_intrinsic(ctx, op, intrinsic, vec![high])?;
760	            combine_reversed_i64_halves(ctx, op, low, high)
761	        }
762	        LegacyBitRewrite::CtpopI128 => {
763	            let (low, high) = split_i128(ctx, op, operands[0]);
764	            let low = call_i64_intrinsic(ctx, op, "llvm_ctpop_i64", vec![low])?;
765	            let high = call_i64_intrinsic(ctx, op, "llvm_ctpop_i64", vec![high])?;
766	            let low = zext_to_i128(ctx, op, low);
767	            let high = zext_to_i128(ctx, op, high);
768	            let sum = llvm::AddOp::new_with_overflow_flag(
769	                ctx,
770	                low,
771	                high,
772	                IntegerOverflowFlagsAttr::default(),
773	            )
774	            .get_operation();
775	            insert_before(ctx, op, sum)
776	        }
777	        LegacyBitRewrite::CtlzI128 | LegacyBitRewrite::CttzI128 => {
778	            let (low, high) = split_i128(ctx, op, operands[0]);
779	            let flag = operands[1];
780	            let (primary, secondary, intrinsic) = if kind == LegacyBitRewrite::CtlzI128 {
781	                (high, low, "llvm_ctlz_i64")
782	            } else {
783	                (low, high, "llvm_cttz_i64")
784	            };
785	            let primary_count = call_i64_intrinsic(ctx, op, intrinsic, vec![primary, flag])?;
786	            let secondary_count = call_i64_intrinsic(ctx, op, intrinsic, vec![secondary, flag])?;
787	            let zero64 = integer_const(ctx, op, 64, 0);
788	            let primary_is_zero = icmp(ctx, op, ICmpPredicateAttr::EQ, primary, zero64);
789	            let sixty_four = integer_const(ctx, op, 64, 64);
790	            let extended_count = llvm::AddOp::new_with_overflow_flag(
791	                ctx,
792	                sixty_four,
793	                secondary_count,
794	                IntegerOverflowFlagsAttr::default(),
795	            )
796	            .get_operation();
797	            let secondary_count = insert_before(ctx, op, extended_count);
798	            let count = select(ctx, op, primary_is_zero, secondary_count, primary_count);
799	            zext_to_i128(ctx, op, count)
800	        }
801	    };
802	    replace_one_result(ctx, op, result)
803	}
