811	fn parse_float_to_int_sat_name(name: &str) -> Option<(FloatToIntSatKind, u32, u32)> {
812	    let (kind, rest) = if let Some(rest) = name.strip_prefix("llvm_fptosi_sat_i") {
813	        (FloatToIntSatKind::Signed, rest)
814	    } else if let Some(rest) = name.strip_prefix("llvm_fptoui_sat_i") {
815	        (FloatToIntSatKind::Unsigned, rest)
816	    } else {
817	        return None;
818	    };
819	    let (int_width, float_width) = rest.split_once("_f")?;
820	    let int_width: u32 = int_width.parse().ok()?;
821	    let float_width: u32 = float_width.parse().ok()?;
822	    (int_width > 0 && int_width <= 128 && matches!(float_width, 16 | 32 | 64)).then_some((
823	        kind,
824	        int_width,
825	        float_width,
826	    ))
827	}
