829	fn validate_float_to_int_sat_call(ctx: &Context, op: Ptr<Operation>, name: &str) -> Result<()> {
830	    let (_, expected_int_width, expected_float_width) =
831	        parse_float_to_int_sat_name(name).expect("validated intrinsic name");
832	    if expected_float_width == 16 {
833	        return pliron::input_err!(
834	            op.deref(ctx).loc(),
835	            "legacy NVVM saturating conversion from f16 is not portable to the supported CUDA 12 legacy dialect"
836	        );
837	    }
838	    let operands: Vec<_> = op.deref(ctx).operands().collect();
839	    if operands.len() != 1 || op.deref(ctx).get_num_results() != 1 {
840	        return pliron::input_err!(
841	            op.deref(ctx).loc(),
842	            "{name} must have one operand and one result"
843	        );
844	    }
845	    let result_width = scalar_integer_width(ctx, op.deref(ctx).get_result(0).get_type(ctx));
846	    let source_width = float_width(ctx, operands[0].get_type(ctx));
847	    if result_width != Some(expected_int_width) || source_width != Some(expected_float_width) {
848	        return pliron::input_err!(
849	            op.deref(ctx).loc(),
850	            "{name} has a signature inconsistent with its overload suffix"
851	        );
852	    }
853	    Ok(())
854	}
855	
856	fn rewrite_float_to_int_sat(ctx: &mut Context, op: Ptr<Operation>, name: &str) -> Result<()> {
857	    let (kind, width, source_width) =
858	        parse_float_to_int_sat_name(name).expect("validated intrinsic name");
859	    let mut source = op.deref(ctx).get_operand(0);
860	
861	    // If f16 support is added later, extending to f32 preserves every f16
862	    // value exactly and allows the same clamp algorithm to be reused.
863	    let compare_width = if source_width == 16 {
864	        let f32_ty: TypeHandle = FP32Type::get(ctx).into();
865	        let extend = llvm::FPExtOp::new(ctx, source, f32_ty);
866	        extend.set_fast_math_flags(ctx, FastmathFlagsAttr::default());
867	        source = insert_before(ctx, op, extend.get_operation());
868	        32
869	    } else {
870	        source_width
871	    };
872	
873	    let result_ty = op.deref(ctx).get_result(0).get_type(ctx);
874	    let raw = match kind {
875	        FloatToIntSatKind::Signed => llvm::FPToSIOp::new(ctx, source, result_ty).get_operation(),
876	        FloatToIntSatKind::Unsigned => llvm::FPToUIOp::new(ctx, source, result_ty).get_operation(),
877	    };
878	    let raw = insert_before(ctx, op, raw);
879	
880	    let (low_float, high_float) = match kind {
881	        FloatToIntSatKind::Signed => (
882	            -(2.0_f64).powi(width as i32 - 1),
883	            (2.0_f64).powi(width as i32 - 1),
884	        ),
885	        FloatToIntSatKind::Unsigned => (0.0, (2.0_f64).powi(width as i32)),
886	    };
887	    let low = float_const(ctx, op, compare_width, low_float)?;
888	    let high = float_const(ctx, op, compare_width, high_float)?;
889	    let is_low = fcmp(ctx, op, FCmpPredicateAttr::OLE, source, low);
890	    let is_high = fcmp(ctx, op, FCmpPredicateAttr::OGE, source, high);
891	    let is_nan = fcmp(ctx, op, FCmpPredicateAttr::UNO, source, source);
892	
893	    let zero = integer_const(ctx, op, width, 0);
894	    let (low_value, high_value) = match kind {
895	        FloatToIntSatKind::Signed => (
896	            integer_const(ctx, op, width, 1_u128 << (width - 1)),
897	            integer_const(ctx, op, width, (1_u128 << (width - 1)) - 1),
898	        ),
899	        FloatToIntSatKind::Unsigned => (zero, integer_const(ctx, op, width, mask_for_width(width))),
900	    };
901	    let high_or_raw = select(ctx, op, is_high, high_value, raw);
902	    let low_or_bounded = select(ctx, op, is_low, low_value, high_or_raw);
903	    let result = select(ctx, op, is_nan, zero, low_or_bounded);
904	    replace_one_result(ctx, op, result)
905	}
