907	fn float_const(ctx: &mut Context, anchor: Ptr<Operation>, width: u32, value: f64) -> Result<Value> {
908	    let attr = match width {
909	        32 => FPSingleAttr::from(value as f32).into(),
910	        64 => FPDoubleAttr::from(value).into(),
911	        _ => {
912	            return pliron::input_err!(
913	                anchor.deref(ctx).loc(),
914	                "legacy float clamp constants support only f32 and f64"
915	            );
916	        }
917	    };
918	    let const_op = llvm::ConstantOp::new(ctx, attr).get_operation();
919	    Ok(insert_before(ctx, anchor, const_op))
920	}
