978	    } else {
979	        i32_ty
980	    };
981	    if value_ty != expected_value_ty
982	        || operands[1].get_type(ctx) != expected_value_ty
983	        || operands[0].get_type(ctx) != i32_ty
984	        || operands[2].get_type(ctx) != i32_ty
985	        || operands[3].get_type(ctx) != i32_ty
986	    {
987	        return pliron::input_err!(
988	            op.deref(ctx).loc(),
989	            "{name} has an invalid legacy-shuffle signature"
990	        );
991	    }
