995	fn rewrite_shuffle(ctx: &mut Context, op: Ptr<Operation>, name: &str) -> Result<()> {
996	    let mode = shuffle_mode(name).expect("validated shuffle name");
997	    let operands: Vec<_> = op.deref(ctx).operands().collect();
998	    let i32_ty: TypeHandle = IntegerType::get(ctx, 32, Signedness::Signless).into();
999	    let i1_ty: TypeHandle = IntegerType::get(ctx, 1, Signedness::Signless).into();
1000	    let struct_ty = llvm_types::StructType::get_unnamed(ctx, vec![i32_ty, i1_ty]);
1001	    let func_ty = llvm_types::FuncType::get(
1002	        ctx,
1003	        struct_ty.into(),
1004	        vec![i32_ty, i32_ty, i32_ty, i32_ty, i32_ty],
1005	        false,
1006	    );
1007	    let parent_block = op.deref(ctx).get_parent_block().ok_or_else(|| {
1008	        pliron::input_error!(op.deref(ctx).loc(), "shuffle call has no parent block")
1009	    })?;
1010	    helpers::ensure_intrinsic_declared(ctx, parent_block, "llvm_nvvm_shfl_sync_i32", func_ty)
1011	        .map_err(|e| pliron::input_error!(op.deref(ctx).loc(), "{e}"))?;
1012	
1013	    let mut value = operands[1];
1014	    if name.ends_with("_f32") {
1015	        let cast_op = llvm::BitcastOp::new(ctx, value, i32_ty).get_operation();
1016	        value = insert_before(ctx, op, cast_op);
1017	    }
1018	    let mode = integer_const(ctx, op, 32, mode as u128);
1019	    let callee = CallOpCallable::Direct(
1020	        "llvm_nvvm_shfl_sync_i32"
1021	            .try_into()
1022	            .expect("static intrinsic name is valid"),
1023	    );
1024	    let call = llvm::CallOp::new(
1025	        ctx,
1026	        callee,
1027	        func_ty,
1028	        vec![operands[0], mode, value, operands[2], operands[3]],
1029	    );
1030	    let aggregate = insert_before(ctx, op, call.get_operation());
1031	    let extracted = llvm::ExtractValueOp::new(ctx, aggregate, vec![0])
1032	        .map_err(|e| pliron::input_error!(op.deref(ctx).loc(), "{e}"))?;
1033	    let mut result = insert_before(ctx, op, extracted.get_operation());
1034	    if name.ends_with("_f32") {
1035	        let f32_ty: TypeHandle = FP32Type::get(ctx).into();
1036	        let cast_op = llvm::BitcastOp::new(ctx, result, f32_ty).get_operation();
1037	        result = insert_before(ctx, op, cast_op);
1038	    }
1039	    replace_one_result(ctx, op, result)
1040	}
