1134	fn rewrite_renamed_call(
1135	    ctx: &mut Context,
1136	    op: Ptr<Operation>,
1137	    replacement_name: &str,
1138	) -> Result<()> {
1139	    let call = Operation::get_op::<llvm::CallOp>(op, ctx).expect("validated call op");
1140	    let args = call.args(ctx);
1141	    let func_ty = call.callee_type(ctx);
1142	    let func_ty = pliron::r#type::TypedHandle::from_handle(func_ty, ctx).map_err(|e| {
1143	        pliron::input_error!(
1144	            op.deref(ctx).loc(),
1145	            "memory intrinsic call has invalid function type: {e}"
1146	        )
1147	    })?;
1148	    let parent_block = op.deref(ctx).get_parent_block().ok_or_else(|| {
1149	        pliron::input_error!(
1150	            op.deref(ctx).loc(),
1151	            "memory intrinsic call has no parent block"
1152	        )
1153	    })?;
1154	    helpers::ensure_intrinsic_declared(ctx, parent_block, replacement_name, func_ty)
1155	        .map_err(|e| pliron::input_error!(op.deref(ctx).loc(), "{e}"))?;
1156	    let replacement = llvm::CallOp::new(
1157	        ctx,
1158	        CallOpCallable::Direct(replacement_name.try_into().map_err(|e| {
1159	            pliron::input_error!(
1160	                op.deref(ctx).loc(),
1161	                "invalid legacy memory intrinsic name: {e}"
1162	            )
1163	        })?),
1164	        func_ty,
1165	        args,
1166	    );
1167	    let result = insert_before(ctx, op, replacement.get_operation());
1168	    replace_one_result(ctx, op, result)
1169	}
