1171	fn remove_obsolete_declarations(
1172	    ctx: &mut Context,
1173	    module: Ptr<Operation>,
1174	    obsolete_names: &[String],
1175	) {
1176	    if obsolete_names.is_empty() {
1177	        return;
1178	    }
1179	    let Some(region) = module.deref(ctx).regions().next() else {
1180	        return;
1181	    };
1182	    let Some(block) = region.deref(ctx).iter(ctx).next() else {
1183	        return;
1184	    };
1185	    let top_level: Vec<_> = block.deref(ctx).iter(ctx).collect();
1186	    for op in top_level {
1187	        let Some(func) = Operation::get_op::<llvm::FuncOp>(op, ctx) else {
1188	            continue;
1189	        };
1190	        let name = func.get_symbol_name(ctx).to_string();
1191	        if obsolete_names.iter().any(|old| old == &name) {
1192	            op.unlink(ctx);
1193	        }
1194	    }
1195	}
