1197	fn verify_legacy_subset(ctx: &Context, module: Ptr<Operation>) -> Result<()> {
1198	    let mut ops = Vec::new();
1199	    collect_ops(ctx, module, &mut ops);
1200	    for op in ops {
1201	        reject_unsupported_op(ctx, op)?;
1202	        if Operation::get_op::<llvm::FNegOp>(op, ctx).is_some() {
1203	            return pliron::input_err!(
1204	                op.deref(ctx).loc(),
1205	                "legacy NVVM legalization left an llvm.fneg behind"
1206	            );
1207	        }
1208	        let nneg: Identifier = NNEG_ATTR
1209	            .try_into()
1210	            .expect("static attribute name is valid");
1211	        let has_true_nneg = op
1212	            .deref(ctx)
1213	            .attributes
1214	            .get::<BoolAttr>(&nneg)
1215	            .is_some_and(|flag| bool::from(flag.clone()));
1216	        if has_true_nneg {
1217	            return pliron::input_err!(
1218	                op.deref(ctx).loc(),
1219	                "legacy NVVM legalization left a true LLVM nneg flag behind"
1220	            );
1221	        }
1222	        let Some(call) = Operation::get_op::<llvm::CallOp>(op, ctx) else {
1223	            continue;
1224	        };
1225	        let CallOpCallable::Direct(callee) = call.callee(ctx) else {
1226	            continue;
1227	        };
1228	        let name = callee.to_string();
1229	        if parse_integer_sat_name(&name).is_some()
1230	            || parse_float_to_int_sat_name(&name).is_some()
1231	            || legacy_bit_rewrite(&name).is_some()
1232	            || shuffle_mode(&name).is_some()
1233	            || vote_mode(&name).is_some()
1234	            || legacy_memory_intrinsic_name(&name).is_some()
1235	        {
1236	            return pliron::input_err!(
1237	                op.deref(ctx).loc(),
1238	                "legacy NVVM legalization left unsupported call @{name} behind"
1239	            );
1240	        }
1241	    }
1242	    Ok(())
1243	}
