/*
 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
 * SPDX-License-Identifier: Apache-2.0
 */

use crate::error::PipelineError;
use crate::verify::verify_operation;
use pliron::context::{Context, Ptr};
use pliron::operation::Operation;
use pliron::printable::Printable;

/// Controls the reusable dialect-mir preparation stage.
#[doc(hidden)]
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MirPreparation {
    /// Promote stack slots to SSA and run annotation-driven loop unrolling.
    pub promote_and_unroll: bool,
}

/// Verify and prepare a dialect-mir module before LLVM lowering.
///
/// The one shared post-translation orchestrator calls this helper for both the
/// rustc and standalone frontends.
#[doc(hidden)]
pub fn prepare_mir_module(
    ctx: &mut Context,
    module: Ptr<Operation>,
    preparation: MirPreparation,
) -> Result<(), PipelineError> {
    verify_operation(ctx, module, "module")?;
    if !preparation.promote_and_unroll {
        return Ok(());
    }

    let mut analyses = pliron::pass_manager::AnalysisManager::default();
    pliron::opts::mem2reg::mem2reg(module, ctx, &mut analyses).map_err(|error| {
        PipelineError::Verification {
            name: "mem2reg".to_string(),
            message: error.disp(ctx).to_string(),
            operation: None,
        }
    })?;
    verify_operation(ctx, module, "module post-mem2reg")?;

    mir_transforms::unroll::unroll_annotated_loops(module, ctx, &mut analyses).map_err(
        |error| PipelineError::Verification {
            name: "loop-unroll".to_string(),
            message: error.disp(ctx).to_string(),
            operation: None,
        },
    )?;
    verify_operation(ctx, module, "module post-unroll")
}

/*
 * SPDX-FileCopyrightText: Copyright (c) 2026 NVIDIA CORPORATION & AFFILIATES. All rights reserved.
 * SPDX-License-Identifier: Apache-2.0
 */

//! Converts lowered LLVM operations to the forms accepted by libNVVM.
//!
//! The transform runs after MIR-to-LLVM lowering and before text export.
//! Pre-Blackwell targets receive LLVM 7-compatible operations. Blackwell and
//! newer targets keep modern operations, apart from NVVM-wide compatibility
//! rewrites.

#![warn(missing_docs)]

mod helpers;
mod legalize;

use llvm_export::export::NvvmIrDialect;
use pliron::{
    context::{Context, Ptr},
    operation::Operation,
    result::Result,
};

/// Legalize a lowered LLVM module for the selected NVVM input dialect.
///
/// Legacy LLVM 7 modules receive the complete compatibility pass. Modern
/// modules retain modern operations but still rewrite integer widths that
/// libNVVM does not accept in bit-manipulation intrinsics.
pub fn legalize_for_nvvm(
    ctx: &mut Context,
    module: Ptr<Operation>,
    dialect: NvvmIrDialect,
) -> Result<()> {
    match dialect {
        NvvmIrDialect::LegacyLlvm7 => legalize::legalize_for_legacy_nvvm(ctx, module),
        NvvmIrDialect::Modern => legalize::legalize_nvvm_bit_intrinsics(ctx, module),
    }
}

