5	
6	//! Smoke test for the `#[unroll]` / `#[unroll(N)]` loop-unroll transform.
7	//!
8	//! The attribute goes directly on the loop it should unroll (the `#[kernel]`
9	//! macro reads it and tags that loop): a function can unroll one loop and leave
10	//! its neighbours alone.
11	//!
12	//! `full_unroll` has a compile-time-constant trip count, so `#[unroll]` should
13	//! unroll it completely and the per-iteration `i & 3` should fold to literals.
14	//! `partial_unroll` has a runtime trip count, so `#[unroll(4)]` unrolls the body
15	//! by 4 and leaves a remainder loop. Both are semantics-preserving; the host
16	//! checks the sums.
17	//!
18	//! Run: cargo oxide run unroll_smoke
19	
20	use cuda_core::{CudaContext, DeviceBuffer, LaunchConfig};
21	use cuda_device::{DisjointSlice, kernel, thread};
22	use cuda_host::cuda_module;
23	
24	#[cuda_module]
25	mod kernels {
26	    use super::*;
27	
28	    /// Full unroll of a constant-trip-count loop. `acc` starts at the thread
29	    /// index and adds `i & 3` for `i` in `0..8` (= 0+1+2+3+0+1+2+3 = 12), so
30	    /// `out[tid] == tid + 12`.
31	    #[kernel]
32	    pub fn full_unroll(mut out: DisjointSlice<u32>) {
33	        let tid = thread::index_1d();
34	        let base = tid.get() as u32;
35	        if let Some(out_elem) = out.get_mut(tid) {
36	            let mut acc: u32 = base;
37	            let mut i: u32 = 0;
38	            #[unroll]
39	            while i < 8 {
40	                acc = acc.wrapping_add(i & 3);
41	                i += 1;
42	            }
43	            *out_elem = acc;
44	        }
45	    }
46	
47	    /// Partial unroll (by 4) of a runtime-trip-count loop: `out[tid]` is the
48	    /// sum `0 + 1 + ... + (n-1) == n*(n-1)/2`.
49	    #[kernel]
50	    pub fn partial_unroll(mut out: DisjointSlice<u32>, n: u32) {
51	        let tid = thread::index_1d();
52	        if let Some(out_elem) = out.get_mut(tid) {
53	            let mut acc: u32 = 0;
54	            let mut i: u32 = 0;
55	            #[unroll(4)]
56	            while i < n {
57	                acc = acc.wrapping_add(i);
58	                i += 1;
59	            }
60	            *out_elem = acc;
61	        }
62	    }
63	
64	    /// Partial unroll (by 4) of a runtime loop whose body uses `i & 3` (the
65	    /// gemm "stage" pattern). After unrolling, the main loop's counter is a
66	    /// multiple of 4, so `(i+j) & 3` should fold to the constants `0,1,2,3`.
67	    /// `out[tid]` is the sum of `i & 3` for `i` in `0..n`.
68	    #[kernel]
69	    pub fn partial_fold(mut out: DisjointSlice<u32>, n: u32) {
70	        let tid = thread::index_1d();
71	        if let Some(out_elem) = out.get_mut(tid) {
72	            let mut acc: u32 = 0;
73	            let mut i: u32 = 0;
74	            #[unroll(4)]
75	            while i < n {
76	                acc = acc.wrapping_add(i & 3);
77	                i += 1;
78	            }
79	            *out_elem = acc;
80	        }
81	    }
82	
83	    /// Partial unroll (by 4) using `i % 4`: a power-of-two modulo, the same stage
84	    /// index as `i & 3` but spelled with `%`. After unrolling, the main loop's
85	    /// counter is a multiple of 4, so `(i + j) % 4` folds to the constants
86	    /// `0,1,2,3` -- this exercises the `% 2^k` arm of the index fold. `out[tid]`
87	    /// is the sum of `i % 4` for `i` in `0..n`.
88	    #[kernel]
89	    pub fn partial_mod(mut out: DisjointSlice<u32>, n: u32) {
90	        let tid = thread::index_1d();
91	        if let Some(out_elem) = out.get_mut(tid) {
92	            let mut acc: u32 = 0;
93	            let mut i: u32 = 0;
94	            #[unroll(4)]
95	            while i < n {
96	                acc = acc.wrapping_add(i % 4);
97	                i += 1;
98	            }
99	            *out_elem = acc;
100	        }
101	    }
102	
103	    /// Full unroll of a loop whose body has **internal control flow** (an
104	    /// `if`/`else`), so the body is several basic blocks, not one. This is the
105	    /// case the earlier single-block unroller could not handle. For `i` in
106	    /// `0..8`: even `i` adds `i` (0+2+4+6 = 12), odd `i` adds 10 (4 * 10 = 40),
107	    /// so `out[tid] == tid + 52`.
108	    #[kernel]
109	    pub fn full_mb(mut out: DisjointSlice<u32>) {
110	        let tid = thread::index_1d();
111	        let base = tid.get() as u32;
112	        if let Some(out_elem) = out.get_mut(tid) {
113	            let mut acc: u32 = base;
114	            let mut i: u32 = 0;
115	            #[unroll]
116	            while i < 8 {
117	                if i & 1 == 0 {
118	                    acc = acc.wrapping_add(i);
119	                } else {
120	                    acc = acc.wrapping_add(10);
121	                }
122	                i += 1;
123	            }
124	            *out_elem = acc;
125	        }
126	    }
127	
128	    /// Partial unroll (by 4) of a runtime loop whose body has internal control
129	    /// flow. For `i` in `0..n`: even `i` adds `i`, odd `i` adds 100. With n=10:
130	    /// even (0+2+4+6+8 = 20) + odd (5 * 100 = 500) = 520.
131	    #[kernel]
132	    pub fn partial_mb(mut out: DisjointSlice<u32>, n: u32) {
133	        let tid = thread::index_1d();
134	        if let Some(out_elem) = out.get_mut(tid) {
135	            let mut acc: u32 = 0;
136	            let mut i: u32 = 0;
137	            #[unroll(4)]
138	            while i < n {
139	                if i & 1 == 0 {
140	                    acc = acc.wrapping_add(i);
141	                } else {
142	                    acc = acc.wrapping_add(100);
143	                }
144	                i += 1;
145	            }
146	            *out_elem = acc;
147	        }
148	    }
149	
150	    /// Full unroll with an early `break`. Only `i = 0..4` reach the addition, so
151	    /// each thread writes its index plus `0+1+2+3+4 = 10`.
152	    #[kernel]
153	    pub fn full_early_break(mut out: DisjointSlice<u32>) {
154	        let tid = thread::index_1d();
155	        let base = tid.get() as u32;
156	        if let Some(out_elem) = out.get_mut(tid) {
157	            let mut acc = base;
158	            let mut i = 0u32;
159	            #[unroll]
160	            while i < 8 {
161	                if i == 5 {
162	                    break;
163	                }
164	                acc = acc.wrapping_add(i);
165	                i += 1;
166	            }
167	            *out_elem = acc;
168	        }
169	    }
170	
171	    /// Partial unroll with two paths back to the header. Both paths increment
172	    /// `i` once, while even values add `i` and odd values add `2*i`.
173	    #[kernel]
174	    pub fn partial_continue_paths(mut out: DisjointSlice<u32>, n: u32) {
175	        let tid = thread::index_1d();
176	        if let Some(out_elem) = out.get_mut(tid) {
177	            let mut acc = 0u32;
178	            let mut i = 0u32;
179	            #[unroll(4)]
180	            while i < n {
181	                let current = i;
182	                i += 1;
183	                if current & 1 == 0 {
184	                    acc = acc.wrapping_add(current);
185	                    continue;
186	                }
187	                acc = acc.wrapping_add(current.wrapping_mul(2));
188	            }
189	            *out_elem = acc;
190	        }
191	    }
192	
193	    /// Partial unroll still rejects early exits. This loop must run normally
194	    /// after the warning and produce the same `0+1+2+3+4 = 10` result.
195	    #[kernel]
196	    pub fn partial_early_break_skipped(mut out: DisjointSlice<u32>, n: u32) {
197	        let tid = thread::index_1d();
198	        if let Some(out_elem) = out.get_mut(tid) {
199	            let mut acc = 0u32;
200	            let mut i = 0u32;
201	            #[unroll(4)]
202	            while i < n {
203	                if i == 5 {
204	                    break;
205	                }
206	                acc = acc.wrapping_add(i);
207	                i += 1;
208	            }
209	            *out_elem = acc;
210	        }
211	    }
212	
213	    /// Regression guard: the loop bound `hi` is **loop-carried** (it changes each
214	    /// iteration), so partial unroll's "does a group of 4 still fit" guard would
215	    /// be unsound. The pass must refuse this loop (a loud warning) and leave it as
216	    /// an ordinary loop, NOT miscompile or crash. For n=10 it runs 5 iterations
217	    /// (i=0..4 before i meets the shrinking hi), so `out[tid] == 0+1+2+3+4 = 10`.
218	    #[kernel]
219	    pub fn carried_bound(mut out: DisjointSlice<u32>, n: u32) {
220	        let tid = thread::index_1d();
221	        if let Some(out_elem) = out.get_mut(tid) {
222	            let mut acc: u32 = 0;
223	            let mut i: u32 = 0;
224	            let mut hi: u32 = n;
225	            #[unroll(4)]
226	            while i < hi {
227	                acc = acc.wrapping_add(i);
228	                i += 1;
229	                hi = hi.wrapping_sub(1);
230	            }
231	            *out_elem = acc;
232	        }
233	    }
234	
235	    /// Nested loops, inner FULLY unrolled. The outer loop (runtime trip `n`) is
236	    /// left alone; its inner `while j < 4` carries `#[unroll]`. The inner body
237	    /// reads the OUTER counter `k` by dominance, which the clone must preserve.
238	    /// Each outer iteration adds `0*k + 1*k + 2*k + 3*k = 6k`; summed over `k` in
239	    /// `0..n`. For n=10: `6 * (0+1+...+9) = 6 * 45 = 270`.
240	    #[kernel]
241	    pub fn nested_full(mut out: DisjointSlice<u32>, n: u32) {
242	        let tid = thread::index_1d();
243	        if let Some(out_elem) = out.get_mut(tid) {
244	            let mut acc: u32 = 0;
245	            let mut k: u32 = 0;
246	            while k < n {
247	                let mut j: u32 = 0;
248	                #[unroll]
249	                while j < 4 {
250	                    acc = acc.wrapping_add(j.wrapping_mul(k));
251	                    j += 1;
252	                }
253	                k += 1;
254	            }
255	            *out_elem = acc;
256	        }
257	    }
258	
259	    /// Nested loops, inner PARTIALLY unrolled (by 2) with a CONSTANT bound. Same
260	    /// outer-counter capture; exercises the partial path nested plus constant-bound
261	    /// re-materialization. Each outer iteration adds `(0+k)+(1+k)+(2+k)+(3+k) =
262	    /// 6 + 4k`; summed over `k` in `0..n`. For n=10: `10*6 + 4*45 = 240`.
263	    #[kernel]
264	    pub fn nested_partial(mut out: DisjointSlice<u32>, n: u32) {
265	        let tid = thread::index_1d();
266	        if let Some(out_elem) = out.get_mut(tid) {
267	            let mut acc: u32 = 0;
268	            let mut k: u32 = 0;
269	            while k < n {
270	                let mut j: u32 = 0;
271	                #[unroll(2)]
272	                while j < 4 {
273	                    acc = acc.wrapping_add(j.wrapping_add(k));
274	                    j += 1;
275	                }
276	                k += 1;
277	            }
278	            *out_elem = acc;
279	        }
280	    }
281	
282	    /// Nested loops, inner partially unrolled with a NON-constant bound that is the
283	    /// OUTER counter `k`. `k` is invariant within the inner loop (it changes only
284	    /// in the outer loop), so partial unroll is sound and `k` dominates the new
285	    /// main header. Inner runs `j` in `0..k`, summing `j` = `k*(k-1)/2`; summed
286	    /// over `k` in `0..n`. For n=10 that is `0+0+1+3+6+10+15+21+28+36 = 120`.
287	    #[kernel]
288	    pub fn nested_var_bound(mut out: DisjointSlice<u32>, n: u32) {
289	        let tid = thread::index_1d();
290	        if let Some(out_elem) = out.get_mut(tid) {
291	            let mut acc: u32 = 0;
292	            let mut k: u32 = 0;
293	            while k < n {
294	                let mut j: u32 = 0;
295	                #[unroll(2)]
296	                while j < k {
297	                    acc = acc.wrapping_add(j);
298	                    j += 1;
299	                }
300	                k += 1;
301	            }
302	            *out_elem = acc;
303	        }
304	    }
305	
306	    /// Unroll a loop that *contains* a loop, FULL path. The OUTER loop (constant
307	    /// trip 4) carries `#[unroll]`; its body holds an inner `while j < 3` that is
308	    /// left alone and cloned wholesale into each of the 4 copies (it stays a
309	    /// loop). The outer `i & 3` folds to 0,1,2,3. Each outer iteration adds
310	    /// `(i & 3) + (0+1+2)`; summed over i in 0..4: (0+1+2+3) + 4*3 = 6 + 12 = 18,
311	    /// so `out[tid] == tid + 18`.
312	    #[kernel]
313	    pub fn outer_full(mut out: DisjointSlice<u32>) {
314	        let tid = thread::index_1d();
315	        let base = tid.get() as u32;
316	        if let Some(out_elem) = out.get_mut(tid) {
317	            let mut acc: u32 = base;
318	            let mut i: u32 = 0;
319	            #[unroll]
320	            while i < 4 {
321	                acc = acc.wrapping_add(i & 3);
322	                let mut j: u32 = 0;
323	                while j < 3 {
324	                    acc = acc.wrapping_add(j);
325	                    j += 1;
326	                }
327	                i += 1;
328	            }
329	            *out_elem = acc;
330	        }
331	    }
332	
333	    /// Unroll a loop that *contains* a loop, PARTIAL path -- the gemm K-loop
334	    /// shape. The OUTER loop (runtime trip `n`) carries `#[unroll(4)]`; its body
335	    /// holds the stage index `i & 3` (which folds to the constants 0,1,2,3 across
336	    /// the 4 copies because the main counter steps by 4) plus an inner
337	    /// `while j < 3` that is cloned wholesale into each copy and stays a loop.
338	    /// Each outer iteration adds `(i & 3) + (0+1+2)`; `out[tid]` is
339	    /// `sum_{i<n}(i & 3) + n*3`.
340	    #[kernel]
341	    pub fn outer_partial(mut out: DisjointSlice<u32>, n: u32) {
342	        let tid = thread::index_1d();
343	        if let Some(out_elem) = out.get_mut(tid) {
344	            let mut acc: u32 = 0;
345	            let mut i: u32 = 0;
346	            #[unroll(4)]
347	            while i < n {
348	                acc = acc.wrapping_add(i & 3);
349	                let mut j: u32 = 0;
350	                while j < 3 {
351	                    acc = acc.wrapping_add(j);
352	                    j += 1;
353	                }
354	                i += 1;
355	            }
356	            *out_elem = acc;
357	        }
358	    }
359	}
360	
361	fn main() {
362	    println!("=== unroll_smoke ===\n");
363	
